function normalize(value) {
  return String(value || "").trim().toLowerCase();
}

function numberOrDefault(value, fallback = 0) {
  if (value === null || value === undefined || value === "") return fallback;
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? numericValue : fallback;
}

function isLoginAllowedSubscriptionStatus(value) {
  return ["active", "trial"].includes(normalize(value));
}

function getOperationalCompanySubscriptionStatus(value) {
  const status = String(value || "Active").trim();
  const normalizedStatus = normalize(status);

  if (["suspended", "cancelled", "canceled", "expired", "inactive"].includes(normalizedStatus)) {
    return status;
  }

  // Trial is a commercial plan/status in Platform Administration,
  // but operational company login must remain Active during the trial period.
  return "Active";
}


function normalizeMatchText(value) {
  return normalize(value)
    .replace(/[\u064B-\u065F\u0670]/g, "")
    .replace(/[أإآ]/g, "ا")
    .replace(/ى/g, "ي")
    .replace(/ة/g, "ه")
    .replace(/[^\p{L}\p{N}]+/gu, " ")
    .trim();
}

function getMatchTokens(value) {
  const stopWords = new Set([
    "and",
    "or",
    "the",
    "of",
    "for",
    "في",
    "من",
    "و",
    "عامل",
    "فني",
  ]);

  return normalizeMatchText(value)
    .split(/\s+/)
    .filter((token) => token.length >= 3 && !stopWords.has(token));
}

function isCompatibleText(left, right) {
  const a = normalizeMatchText(left);
  const b = normalizeMatchText(right);

  if (!a || !b) return true;
  if (a === b || a.includes(b) || b.includes(a)) return true;

  const aTokens = getMatchTokens(a);
  const bTokens = getMatchTokens(b);
  if (!aTokens.length || !bTokens.length) return false;

  const shared = aTokens.filter((token) => bTokens.includes(token));
  return shared.length >= 1;
}

function isCompatibleVisaLineForRequestLine(reqLine, visaLine) {
  return (
    isCompatibleText(reqLine.profession, visaLine.profession) &&
    normalize(reqLine.nationality) === normalize(visaLine.nationality) &&
    (!reqLine.gender || !visaLine.gender || normalize(reqLine.gender) === normalize(visaLine.gender))
  );
}

function isSaudiNationality(value) {
  const text = normalize(value || "");
  const compact = text.replace(/[\s\-_()/]+/g, "");

  const arabicCompact = text
    .replace(/[\u064B-\u065F\u0670]/g, "")
    .replace(/[أإآ]/g, "ا")
    .replace(/ى/g, "ي")
    .replace(/ة/g, "ه")
    .replace(/[\s\-_()/]+/g, "");

  return (
    [
      "saudi",
      "saudiarabia",
      "ksa",
      "kingdomofsaudiarabia",
    ].includes(compact) ||
    compact.includes("saudi") ||
    [
      "سعودي",
      "سعوديه",
      "السعوديه",
      "المملكهالعربيهالسعوديه",
    ].includes(arabicCompact) ||
    arabicCompact.includes("سعود")
  );
}

function isSaudiRequest(request) {
  return request?.recruitment_type === "Saudi" || isSaudiNationality(request?.nationality);
}

function isSaudiCandidate(candidate, requests = []) {
  const relatedRequest = requests.find((r) => String(r.request_no || "") === String(candidate?.request_no || ""));
  return isSaudiRequest(relatedRequest) || isSaudiNationality(candidate?.nationality);
}


function getRowValue(row, keys) {
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && String(row[key]).trim() !== "") return String(row[key]).trim();
  }
  return "";
}

function isArabicText(value) {
  return /[\u0600-\u06FF]/.test(String(value || ""));
}

function isAnyValue(value) {
  const normalizedValue = normalizeMatchText(value);
  return !normalizedValue || ["any", "all", "na", "n a", "not specified", "غير محدد", "الكل", "جميع", "اي", "اى"].includes(normalizedValue);
}

function getTextSimilarity(left, right) {
  const a = normalizeMatchText(left);
  const b = normalizeMatchText(right);
  if (!a || !b) return 0;
  if (a === b) return 1;
  if (a.includes(b) || b.includes(a)) return 0.92;

  const aTokens = getMatchTokens(a);
  const bTokens = getMatchTokens(b);
  const tokenUnion = new Set([...aTokens, ...bTokens]);
  const sharedTokens = aTokens.filter((token) => bTokens.includes(token));
  const tokenScore = tokenUnion.size ? sharedTokens.length / tokenUnion.size : 0;

  const maxLength = Math.max(a.length, b.length, 1);
  const distance = levenshteinDistance(a, b);
  const editScore = Math.max(0, 1 - distance / maxLength);

  return Math.max(tokenScore, editScore);
}

function levenshteinDistance(a, b) {
  const left = String(a || "");
  const right = String(b || "");
  const matrix = Array.from({ length: left.length + 1 }, (_, i) => [i]);

  for (let j = 1; j <= right.length; j += 1) matrix[0][j] = j;

  for (let i = 1; i <= left.length; i += 1) {
    for (let j = 1; j <= right.length; j += 1) {
      const cost = left[i - 1] === right[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }

  return matrix[left.length][right.length];
}


