const executiveDashboard = useMemo(() => {
  const excludedCandidateStatuses = [
    "Rejected",
    "Interview Failed",
    "Cancelled",
    "Medical Failed",
    "Medical Fail",
  ];

  const isActiveCandidate = (candidate) =>
    !excludedCandidateStatuses.includes(candidate.status);

  const activeCandidates = candidates.filter(isActiveCandidate);

  const totalRequired = requests.reduce(
    (sum, request) => sum + getRequestTotalQty(request),
    0
  );

  const saudiRequests = requests.filter(isSaudiRequest);
  const foreignRequests = requests.filter((request) => !isSaudiRequest(request));
  const saudiRequired = saudiRequests.reduce((sum, request) => sum + getRequestTotalQty(request), 0);
  const foreignRequired = foreignRequests.reduce((sum, request) => sum + getRequestTotalQty(request), 0);
  const saudiCandidates = activeCandidates.filter((candidate) => isSaudiCandidate(candidate, requests));
  const foreignCandidates = activeCandidates.filter((candidate) => !isSaudiCandidate(candidate, requests));
  const saudiJoined = saudiCandidates.filter((candidate) => candidate.status === "Joined" || candidate.offer_status === "Joined" || candidate.joining_date).length;
  const foreignJoined = foreignCandidates.filter((candidate) => candidate.status === "Joined").length;
  const saudizationRate = activeCandidates.length ? Math.round((saudiCandidates.length / activeCandidates.length) * 100) : 0;

  const completedRequests = requests.filter((request) => {
    const qty = Number(request.quantity || request.qty || 0);
    if (!qty) return false;
    const joinedCount = activeCandidates.filter(
      (candidate) =>
        String(candidate.request_no || "") === String(request.request_no || "") &&
        candidate.status === "Joined"
    ).length;
    return joinedCount >= qty || request.status === "Completed" || request.status === "Closed";
  }).length;

  const totalJoined = activeCandidates.filter((candidate) => candidate.status === "Joined").length;
  const recruitmentProgress = totalRequired
    ? Math.round((activeCandidates.length / totalRequired) * 100)
    : 0;

  const allocatedVisas = visaAllocations.reduce(
    (sum, allocation) => sum + Number(allocation.allocated_qty || 0),
    0
  );

  const totalVisaQty = visaRecords.reduce(
    (sum, visa) => sum + Number(visa.quantity || 0),
    0
  );

  const openAuthorizations = visaAuthorizations.filter(
    (authorization) => authorization.status !== "Cancelled"
  ).length;

  const cancelledAuthorizations = visaAuthorizations.filter(
    (authorization) => authorization.status === "Cancelled"
  ).length;

  const interviewPassedCandidateIds = new Set(
    interviews
      .filter((interview) => interview.status === "Passed")
      .map((interview) => String(interview.candidate_id || interview.passport_no || interview.candidate_name || ""))
      .filter(Boolean)
  );

  const interviewPassed = activeCandidates.filter(
    (candidate) =>
      candidate.status === "Interview Passed" ||
      candidate.status === "Selected" ||
      interviewPassedCandidateIds.has(String(candidate.id || "")) ||
      interviewPassedCandidateIds.has(String(candidate.passport_no || "")) ||
      interviewPassedCandidateIds.has(String(candidate.candidate_name || ""))
  ).length;

  const medicalPassed = activeCandidates.filter(
    (candidate) =>
      ["Passed", "Fit", "Medical Passed"].includes(candidate.medical_status) ||
      ["Medical Passed", "Visa Stamped", "Ticket Booked", "Departure", "Arrived KSA", "Arrived", "Joined"].includes(candidate.status)
  ).length;

  const ticketsIssued = activeCandidates.filter(
    (candidate) => Boolean(candidate.ticket_no) || candidate.status === "Ticket Booked"
  ).length;

  const arrived = activeCandidates.filter(
    (candidate) =>
      Boolean(candidate.arrival_date) ||
      candidate.status === "Arrived KSA" ||
      candidate.status === "Arrived" ||
      candidate.status === "Joined"
  ).length;

  const joined = activeCandidates.filter((candidate) => candidate.status === "Joined").length;

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const next30 = new Date(today);
  next30.setDate(next30.getDate() + 30);

  const arrivalsNext30Days = activeCandidates
    .filter((candidate) => {
      if (!candidate.arrival_date) return false;
      const arrivalDate = new Date(candidate.arrival_date);
      return arrivalDate >= today && arrivalDate <= next30;
    })
    .sort((a, b) => new Date(a.arrival_date) - new Date(b.arrival_date))
    .slice(0, 20)
    .map((candidate) => ({
      date: new Date(candidate.arrival_date).toLocaleDateString("en-GB"),
      candidate: candidate.candidate_name || "-",
      project: candidate.project || "-",
      request_no: candidate.request_no || "-",
      status: candidate.status || "-",
    }));

  const projectMap = new Map();

  requests.forEach((request) => {
    const project = request.project_name || request.project || "Unassigned";
    const current = projectMap.get(project) || {
      project,
      required: 0,
      active: 0,
      arrived: 0,
      joined: 0,
      requestNos: new Set(),
    };
    current.required += Number(request.quantity || request.qty || 0);
    if (request.request_no) current.requestNos.add(String(request.request_no));
    projectMap.set(project, current);
  });

  activeCandidates.forEach((candidate) => {
    const byRequest = Array.from(projectMap.values()).find((project) =>
      project.requestNos.has(String(candidate.request_no || ""))
    );
    const projectName = byRequest?.project || candidate.project || "Unassigned";
    const current = projectMap.get(projectName) || {
      project: projectName,
      required: 0,
      active: 0,
      arrived: 0,
      joined: 0,
      requestNos: new Set(),
    };

    current.active += 1;
    if (
      Boolean(candidate.arrival_date) ||
      candidate.status === "Arrived KSA" ||
      candidate.status === "Arrived" ||
      candidate.status === "Joined"
    ) {
      current.arrived += 1;
    }
    if (candidate.status === "Joined") current.joined += 1;
    projectMap.set(projectName, current);
  });

  const topProjects = Array.from(projectMap.values())
    .map((project) => ({
      project: project.project,
      required: project.required,
      active: project.active,
      arrived: project.arrived,
      joined: project.joined,
      progress: project.required ? Math.round((project.active / project.required) * 100) : 0,
      arrivalProgress: project.required ? Math.round((project.arrived / project.required) * 100) : 0,
    }))
    .sort((a, b) => b.required - a.required)
    .slice(0, 8);

  const recruitmentFunnel = [
    { stage: "Required", value: totalRequired },
    { stage: "Active Candidates", value: activeCandidates.length },
    { stage: "Interview Passed", value: interviewPassed },
    { stage: "Medical Passed", value: medicalPassed },
    { stage: "Tickets Issued", value: ticketsIssued },
    { stage: "Arrived KSA", value: arrived },
    { stage: "Joined", value: joined },
  ];

  return {
    totalRequired,
    openRequests: requests.filter((request) => ["Open", "Under Recruitment", "Interview Stage", "Visa Process"].includes(request.status)).length,
    underRecruitment: requests.filter((request) => request.status === "Under Recruitment").length,
    completedRequests,
    recruitmentProgress,
    saudiRequests: saudiRequests.length,
    foreignRequests: foreignRequests.length,
    saudiRequired,
    foreignRequired,
    saudiCandidates: saudiCandidates.length,
    foreignCandidates: foreignCandidates.length,
    saudiJoined,
    foreignJoined,
    saudizationRate,
    totalVisaQty,
    allocatedVisas,
    availableVisas: Math.max(totalVisaQty - allocatedVisas, 0),
    openAuthorizations,
    cancelledAuthorizations,
    activeCandidates: activeCandidates.length,
    interviewPassed,
    medicalPassed,
    ticketsIssued,
    arrived,
    joined,
    requestsWithoutVisa: reports.requestsWithoutVisa.length,
    visasWithoutAuthorization: reports.visasWithoutAuthorization.length,
    candidatesWithoutInterviews: reports.candidatesWithoutInterviews.length,
    lateSlaItems: reports.lateItems.length,
    topProjects,
    arrivalsNext30Days,
    recruitmentFunnel,
  };
}, [requests, requestLines, visaRecords, visaAllocations, visaAuthorizations, candidates, interviews, reports]);

 async function generateRequestNo() {
  const year = new Date().getFullYear();

  // IMPORTANT:
  // The database has a unique constraint on requests.request_no.
  // Therefore the next number must be generated from all visible request numbers,
  // not only from the current company, otherwise another company may already own
  // the same REQ-year-number and Supabase will reject the save.
  const { data, error } = await supabase
    .from("requests")
    .select("request_no")
    .like("request_no", `REQ-${year}-%`)
    .range(0, 10000);

  if (error) {
    console.warn("generateRequestNo failed:", error.message);
    throw new Error(`Could not generate request number: ${error.message}`);
  }

  const maxNumber = (data || []).reduce((max, row) => {
    const requestNo = String(row.request_no || "").trim();
    const match = requestNo.match(new RegExp(`^REQ-${year}-(\\d+)$`));
    if (!match) return max;

    const value = Number(match[1] || 0);
    return Number.isFinite(value) && value > max ? value : max;
  }, 0);

  return `REQ-${year}-${String(maxNumber + 1).padStart(4, "0")}`;
}

function isDuplicateRequestNoError(error) {
  const message = String(error?.message || "").toLowerCase();
  const details = String(error?.details || "").toLowerCase();
  const constraint = String(error?.constraint || "").toLowerCase();

  return (
    error?.code === "23505" &&
    (
      message.includes("request") ||
      details.includes("request") ||
      constraint.includes("requests_request_no_unique")
    )
  ) || message.includes("requests_request_no_unique");
}

  async function addAudit(requestId, action, details) {
    if (!requestId) return;
    await supabase.from("request_audit_logs").insert([withCompany({ request_id: requestId, action, details, changed_by: "Recruitment" })]);
    loadAuditLogs();
  }

  function getRequestLinesForRequest(request) {
    if (!request) return [];

    const storedLines = requestLines
      .filter(
        (line) =>
          String(line.request_id || "") === String(request.id || "") ||
          String(line.request_no || "") === String(request.request_no || "")
      )
      .sort((a, b) => Number(a.line_no || 0) - Number(b.line_no || 0));

    if (storedLines.length > 0) return storedLines;

    if (request.profession || request.quantity || request.nationality || request.gender) {
      return [
        {
          id: `${request.id || request.request_no}-legacy`,
          request_id: request.id,
          request_no: request.request_no,
          line_no: 1,
          profession: request.profession || "",
          nationality: request.nationality || "",
          gender: request.gender || "",
          quantity: Number(request.quantity || request.qty || 0),
          salary: request.salary || "",
          interview_required: request.interview_required || "Required",
          interview_type: request.interview_type || "Online",
          notes: request.notes || "",
        },
      ];
    }

    return [];
  }

  function getRequestTotalQty(request) {
    const lines = getRequestLinesForRequest(request);
    const total = lines.reduce((sum, line) => sum + Number(line.quantity || 0), 0);
    return total || Number(request?.quantity || request?.qty || 0);
  }

  function getRequestLineSummary(request, field) {
    const values = getRequestLinesForRequest(request)
      .map((line) => line[field])
      .filter(Boolean);

    const unique = Array.from(new Set(values));

    if (unique.length === 0) return "-";
    if (unique.length === 1) return unique[0];
    return `Multiple (${unique.length})`;
  }

  function getRequestNotificationLines(request, fallbackLines = []) {
    const sourceLines = fallbackLines.length > 0 ? fallbackLines : getRequestLinesForRequest(request);

    return sourceLines
      .map((line, index) => ({
        ...line,
        line_no: line.line_no || index + 1,
        profession: line.profession || "",
        nationality: line.nationality || "",
        gender: line.gender || "",
        quantity: Number(line.quantity || 0),
        salary: line.salary || "",
        notes: line.notes || "",
      }))
      .filter((line) => line.profession && line.quantity > 0 && !isSaudiNationality(line.nationality));
  }

  function getNotificationLineKey(line, index = 0) {
    return String(
      line?.id ||
      line?.request_line_id ||
      `${line?.request_no || "line"}-${line?.line_no || index + 1}-${line?.profession || ""}-${line?.nationality || ""}-${line?.gender || ""}`
    );
  }

  function getSelectedNotificationLines(notification = requestAgencyNotification) {
    if (!notification?.lines?.length) return [];
    const selectedLineKeys = new Set((notification.selectedLineKeys || []).map(String));
    if (selectedLineKeys.size === 0) return [];

    return notification.lines.filter((line, index) =>
      selectedLineKeys.has(getNotificationLineKey(line, index))
    );
  }

  function getNotificationLineMatchingAgencyCount(line) {
    return getActiveAgenciesForNotification().filter((agency) => agencyMatchesRequestLine(agency, line)).length;
  }

  function getNationalityMatchValues(value) {
    const raw = String(value || "").trim();
    const values = new Set();
    const addValue = (item) => {
      const normalized = normalizeMatchText(item);
      if (normalized) values.add(normalized);
    };

    addValue(raw);

    const parenthesisMatch = raw.match(/\(([^)]+)\)/);
    if (parenthesisMatch?.[1]) addValue(parenthesisMatch[1]);

    countries.forEach((country) => {
      const countryValues = [country.name, country.nationality].filter(Boolean);
      const matched = countryValues.some((item) => {
        const normalizedItem = normalizeMatchText(item);
        const normalizedRaw = normalizeMatchText(raw);
        return normalizedItem && normalizedRaw && (normalizedRaw.includes(normalizedItem) || normalizedItem.includes(normalizedRaw));
      });

      if (matched) {
        countryValues.forEach(addValue);
      }
    });

    return Array.from(values);
  }

  function agencyMatchesRequestLine(agency, line) {
    if (!agency || normalize(agency.status || "Active") === "inactive") return false;
    if (!line || isSaudiNationality(line.nationality)) return false;

    const agencyCountryValues = [agency.country, agency.office_country, agency.nationality]
      .map((item) => normalizeMatchText(item))
      .filter(Boolean);

    if (agencyCountryValues.length === 0) return false;

    const lineValues = getNationalityMatchValues(line.nationality);

    return agencyCountryValues.some((agencyValue) =>
      lineValues.some((lineValue) =>
        agencyValue === lineValue || agencyValue.includes(lineValue) || lineValue.includes(agencyValue)
      )
    );
  }

  function getAgencyMatchedLines(agency, lines = []) {
    return lines.filter((line) => agencyMatchesRequestLine(agency, line));
  }

  function getActiveAgenciesForNotification() {
    return agencies
      .filter((agency) => normalize(agency.status || "Active") !== "inactive")
      .sort((a, b) => String(a.country || "").localeCompare(String(b.country || "")) || String(a.name || "").localeCompare(String(b.name || "")));
  }

  function getMatchingAgenciesForRequestLines(lines = []) {
    return getActiveAgenciesForNotification().filter((agency) =>
      lines.some((line) => agencyMatchesRequestLine(agency, line))
    );
  }

  function formatRequestLineForNotification(line) {
    return `${line.profession || "-"} | ${line.nationality || "-"} | ${line.gender || "-"} | Qty: ${Number(line.quantity || 0)}`;
  }

  function buildAgencyRequestNotificationMessage(request, lines = [], agency = {}) {
    const lineSummary = lines.map(formatRequestLineForNotification).join("\n");
    return `New manpower request sourcing alert. Please start searching for suitable candidates based on the following request requirements.\n\nRequest No: ${request?.request_no || "-"}\nProject: ${request?.project_name || request?.project || "-"}\nPriority: ${request?.priority || "Normal"}\nAgency: ${agency?.name || "-"}\n\nRequired Lines:\n${lineSummary || "-"}\n\nThis is an early sourcing notification only. Formal authorization and final candidate submission must follow the approved VisaFlow process.`;
  }


  function getAgencySlaDays(agencyName = "") {
    const activeAgreement = agencyAgreements.find((agreement) =>
      normalize(agreement.agency_name) === normalize(agencyName) &&
      ["active", "pending signature", "draft"].includes(normalize(agreement.status || "Active"))
    );

    return Number(activeAgreement?.sla_days || 60);
  }

  function addDaysToIso(dateValue, days = 0) {
    const date = new Date(dateValue || new Date());
    date.setDate(date.getDate() + Number(days || 0));
    return date.toISOString();
  }

  function isAgencyRequestNotification(item) {
    return item?.type === "NEW_REQUEST_AGENCY_ALERT";
  }

  function getAgencyRequestDecision(item) {
    const data = item?.data || {};
    return item?.response_status || data.response_status || data.agency_decision || "Pending";
  }

  function getAgencyRequestSlaInfo(item) {
    const data = item?.data || {};
    const decision = getAgencyRequestDecision(item);
    const slaStartedAt = item?.sla_started_at || data.sla_started_at;
    const slaDaysValue = Number(item?.sla_days || data.sla_days || 60);
    const slaDueAtValue = item?.sla_due_at || data.sla_due_at || (slaStartedAt ? addDaysToIso(slaStartedAt, slaDaysValue) : null);

    if (decision !== "Accepted" || !slaStartedAt) {
      return {
        running: false,
        label: decision === "Rejected" ? "Rejected - SLA not started" : "Waiting for agency acceptance",
      };
    }

    const startedAt = new Date(slaStartedAt);
    const dueAt = new Date(slaDueAtValue);
    const today = new Date();
    const elapsedDays = Math.max(0, Math.floor((today - startedAt) / (1000 * 60 * 60 * 24)));
    const remainingDays = Math.ceil((dueAt - today) / (1000 * 60 * 60 * 24));

    return {
      running: true,
      slaDays: slaDaysValue,
      startedAt: slaStartedAt,
      dueAt: dueAt.toISOString(),
      elapsedDays,
      remainingDays,
      label: remainingDays < 0
        ? `SLA Overdue by ${Math.abs(remainingDays)} day(s)`
        : `SLA Running: ${elapsedDays}/${slaDaysValue} day(s), ${remainingDays} remaining`,
    };
  }

  function renderAgencyRequestDecisionCell(item) {
    if (!isAgencyRequestNotification(item)) return <span>-</span>;

    const decision = getAgencyRequestDecision(item);
    const sla = getAgencyRequestSlaInfo(item);
    const data = item?.data || {};

    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 6, minWidth: 210 }}>
        <div>
          <Badge value={decision} />
        </div>
        <div style={{ fontSize: 12, color: sla.running ? "#0369a1" : decision === "Rejected" ? "#dc2626" : "#64748b", fontWeight: 700 }}>
          {sla.label}
        </div>
        {data.responded_at && (
          <div style={{ fontSize: 11, color: "#64748b" }}>
            Responded: {new Date(data.responded_at).toLocaleString()}
          </div>
        )}
        {data.response_notes && (
          <div style={{ fontSize: 11, color: "#64748b" }}>
            Note: {data.response_notes}
          </div>
        )}
      </div>
    );
  }

  async function handleAgencyRequestNotificationResponse(item, decision) {
    if (!item?.id) return alert("Notification was not found.");
    if (currentRole !== "Agency") return alert("Only agency users can accept or reject this request alert.");
    if (!isAgencyRequestNotification(item)) return alert("This notification is not an agency request alert.");

    const currentDecision = getAgencyRequestDecision(item);
    if (["Accepted", "Rejected"].includes(currentDecision)) {
      return alert(`This request alert is already ${currentDecision}.`);
    }

    let responseNotes = "";
    if (decision === "Rejected") {
      responseNotes = window.prompt("Rejection reason / سبب الرفض:", "Not available to source this request") || "Rejected by agency";
    } else if (!window.confirm("Accept this request and start SLA now?")) {
      return;
    }

    const now = new Date().toISOString();
    const existingData = item.data || {};
    const agencyName = existingData.agency_name || item.agency_name || currentUser?.agency_name || "Agency";
    const slaDays = decision === "Accepted" ? getAgencySlaDays(agencyName) : Number(existingData.sla_days || 60);
    const slaDueAt = decision === "Accepted" ? addDaysToIso(now, slaDays) : existingData.sla_due_at || null;

    const nextData = {
      ...existingData,
      response_status: decision,
      agency_decision: decision,
      responded_at: now,
      responded_by_name: currentUser?.name || currentUser?.email || "Agency User",
      responded_by_email: currentUser?.email || "",
      response_notes: responseNotes,
      sla_status: decision === "Accepted" ? "Running" : "Not Started",
      sla_started_at: decision === "Accepted" ? now : null,
      sla_days: slaDays,
      sla_due_at: slaDueAt,
    };

    const { error } = await supabase
      .from("notification_events")
      .update({
        status: "Read",
        read_at: now,
        agency_name: agencyName,
        request_no: existingData.request_no || item.request_no || "",
        response_status: decision,
        response_at: now,
        rejection_reason: decision === "Rejected" ? responseNotes : "",
        sla_started_at: nextData.sla_started_at,
        sla_days: nextData.sla_days,
        sla_due_at: nextData.sla_due_at,
        data: nextData,
      })
      .eq("id", item.id)
      .eq("company_id", currentCompanyId);

    if (error) return alert(`Agency response failed: ${error.message}`);

    const responseTitle = `${agencyName} ${decision} Request ${existingData.request_no || ""}`.trim();
    const responseMessage = decision === "Accepted"
      ? `${agencyName} accepted request ${existingData.request_no || "-"}. SLA started now for ${slaDays} day(s). Due date: ${new Date(slaDueAt).toLocaleDateString()}.`
      : `${agencyName} rejected request ${existingData.request_no || "-"}. Reason: ${responseNotes}`;

    try {
      await triggerExternalNotification("AGENCY_REQUEST_RESPONSE", {
        company_id: currentCompanyId,
        user_id: null,
        agency_id: null,
        original_agency_id: item.agency_id || existingData.agency_id || currentUser?.agency_id || null,
        agency_name: agencyName,
        title: responseTitle,
        message: responseMessage,
        priority: decision === "Accepted" ? "High" : "Medium",
        related_table: "requests",
        related_id: existingData.request_id || item.related_id || "",
        request_id: existingData.request_id || "",
        request_no: existingData.request_no || "",
        response_status: decision,
        response_notes: responseNotes,
        sla_started_at: nextData.sla_started_at,
        sla_days: nextData.sla_days,
        sla_due_at: nextData.sla_due_at,
      });
    } catch (notifyError) {
      console.warn("Company response notification failed", notifyError?.message || notifyError);
    }

    try {
      await dispatchVisaFlowEmail({
        type: "AGENCY_REQUEST_RESPONSE_EMAIL",
        to: getCompanyEmailRecipient("notifications"),
        subject: responseTitle,
        text: responseMessage,
        html: buildEmailCardHtml(responseTitle, [responseMessage], decision === "Accepted" ? "SLA counting has started from the agency acceptance time." : "No SLA will be counted for this rejected request alert."),
        payload: nextData,
      });
    } catch (emailError) {
      console.warn("Agency response email failed", emailError?.message || emailError);
    }

    await loadNotifications();
    if (canViewEmailAdministration) await loadEmailLogs();
    alert(decision === "Accepted" ? "Request accepted. SLA has started." : "Request rejected.");
  }

  function openRequestAgencyNotification(request, fallbackLines = []) {
    if (!canNotifyAgencies) return alert("You do not have permission to notify agencies.");

    const lines = getRequestNotificationLines(request, fallbackLines);
    if (lines.length === 0) {
      return alert("No foreign request lines found for agency notification.");
    }

    const selectedLineKeys = lines.map((line, index) => getNotificationLineKey(line, index));
    const matchingAgencies = getMatchingAgenciesForRequestLines(lines);

    setRequestAgencyNotification({
      request,
      lines,
      selectedLineKeys,
      selectedAgencyIds: matchingAgencies.map((agency) => String(agency.id)),
      createdAt: new Date().toISOString(),
    });

    setRequestAgencyNotificationMessage(
      matchingAgencies.length > 0
        ? `${lines.length} request line(s) selected and ${matchingAgencies.length} matching agenc${matchingAgencies.length === 1 ? "y" : "ies"} selected based on nationality.`
        : `${lines.length} request line(s) selected. No matching agency found by nationality. Please select agencies manually.`
    );

    setTimeout(() => {
      document.getElementById("request-agency-notification-panel")?.scrollIntoView({ behavior: "smooth", block: "start" });
    }, 100);
  }

  function syncAgenciesForSelectedNotificationLines(prev, nextSelectedLineKeys) {
    const selectedLineKeys = new Set((nextSelectedLineKeys || []).map(String));
    const selectedLines = (prev.lines || []).filter((line, index) =>
      selectedLineKeys.has(getNotificationLineKey(line, index))
    );

    return {
      ...prev,
      selectedLineKeys: Array.from(selectedLineKeys),
      selectedAgencyIds: getMatchingAgenciesForRequestLines(selectedLines).map((agency) => String(agency.id)),
    };
  }

  function toggleRequestAgencyNotificationLine(lineKey) {
    setRequestAgencyNotification((prev) => {
      if (!prev) return prev;
      const selected = new Set((prev.selectedLineKeys || []).map(String));
      const key = String(lineKey);
      if (selected.has(key)) selected.delete(key);
      else selected.add(key);
      return syncAgenciesForSelectedNotificationLines(prev, Array.from(selected));
    });
  }

  function selectAllRequestNotificationLines() {
    setRequestAgencyNotification((prev) => {
      if (!prev) return prev;
      const allLineKeys = (prev.lines || []).map((line, index) => getNotificationLineKey(line, index));
      return syncAgenciesForSelectedNotificationLines(prev, allLineKeys);
    });
  }

  function clearRequestNotificationLines() {
    setRequestAgencyNotification((prev) => {
      if (!prev) return prev;
      return { ...prev, selectedLineKeys: [], selectedAgencyIds: [] };
    });
  }

  function toggleRequestAgencyNotificationAgency(agencyId) {
    setRequestAgencyNotification((prev) => {
      if (!prev) return prev;
      const id = String(agencyId);
      const selected = new Set((prev.selectedAgencyIds || []).map(String));
      if (selected.has(id)) selected.delete(id);
      else selected.add(id);
      return { ...prev, selectedAgencyIds: Array.from(selected) };
    });
  }

  function selectMatchingAgenciesForCurrentNotification() {
    setRequestAgencyNotification((prev) => {
      if (!prev) return prev;
      const selectedLines = getSelectedNotificationLines(prev);
      return {
        ...prev,
        selectedAgencyIds: getMatchingAgenciesForRequestLines(selectedLines).map((agency) => String(agency.id)),
      };
    });
  }

  function selectAllAgenciesForCurrentNotification() {
    setRequestAgencyNotification((prev) => {
      if (!prev) return prev;
      return {
        ...prev,
        selectedAgencyIds: getActiveAgenciesForNotification().map((agency) => String(agency.id)),
      };
    });
  }

  async function sendRequestAgencyNotifications() {
    if (!requestAgencyNotification?.request) return alert("No saved request selected for agency notification.");
    if (!canNotifyAgencies) return alert("You do not have permission to notify agencies.");

    const selectedLines = getSelectedNotificationLines(requestAgencyNotification);
    if (selectedLines.length === 0) return alert("Please select at least one profession / nationality line to notify.");

    const selectedAgencyIds = new Set((requestAgencyNotification.selectedAgencyIds || []).map(String));
    const selectedAgencies = getActiveAgenciesForNotification().filter((agency) => selectedAgencyIds.has(String(agency.id)));

    if (selectedAgencies.length === 0) return alert("Please select at least one agency.");

    setRequestAgencyNotificationSending(true);
    setRequestAgencyNotificationMessage("Sending agency notifications...");

    try {
      let notificationCreated = 0;
      let emailSent = 0;
      let emailSkipped = 0;
      let emailFailed = 0;
      const emailErrors = [];

      for (const agency of selectedAgencies) {
        const matchedLines = getAgencyMatchedLines(agency, selectedLines);
        const agencyLines = matchedLines.length > 0 ? matchedLines : selectedLines;
        const title = `New Request Sourcing Alert - ${requestAgencyNotification.request.request_no || "Request"}`;
        const message = buildAgencyRequestNotificationMessage(requestAgencyNotification.request, agencyLines, agency);
        const notificationPayload = {
          company_id: currentCompanyId,
          agency_id: agency.id,
          agency_name: agency.name || "",
          agency_country: agency.country || "",
          title,
          message,
          priority: requestAgencyNotification.request.priority || "High",
          related_table: "requests",
          related_id: requestAgencyNotification.request.id || "",
          request_id: requestAgencyNotification.request.id || "",
          request_no: requestAgencyNotification.request.request_no || "",
          project_name: requestAgencyNotification.request.project_name || requestAgencyNotification.request.project || "",
          response_required: true,
          response_status: "Pending",
          agency_decision: "Pending",
          sla_status: "Not Started",
          sla_started_at: null,
          sla_days: getAgencySlaDays(agency.name),
          sla_due_at: null,
          sent_at: new Date().toISOString(),
          email_to: agency.email || "",
          lines: agencyLines.map((line) => ({
            line_no: line.line_no || "",
            profession: line.profession || "",
            nationality: line.nationality || "",
            gender: line.gender || "",
            quantity: Number(line.quantity || 0),
            salary: line.salary || "",
            notes: line.notes || "",
          })),
        };

        await triggerExternalNotification("NEW_REQUEST_AGENCY_ALERT", notificationPayload);
        notificationCreated += 1;

        if (!agency.email) {
          emailSkipped += 1;
          continue;
        }

        try {
          await dispatchVisaFlowEmail({
            type: "NEW_REQUEST_AGENCY_ALERT_EMAIL",
            to: agency.email,
            replyTo: getCompanyEmailRecipient("notifications"),
            subject: title,
            text: message,
            html: buildEmailCardHtml(title, message.split(/\n+/).filter(Boolean), "Please login to VisaFlow Office Portal > Notifications and Accept or Reject this request. SLA will start only after acceptance."),
            payload: notificationPayload,
          });
          emailSent += 1;
        } catch (emailError) {
          emailFailed += 1;
          emailErrors.push(`${agency.name || agency.email}: ${emailError.message}`);
          console.warn("Agency notification email failed", agency.email, emailError.message);
        }
      }

      await addAudit(
        requestAgencyNotification.request.id,
        "Agency Notification Sent",
        `Notification Center: ${notificationCreated}. Emails sent: ${emailSent}. Email failed: ${emailFailed}. Email skipped: ${emailSkipped}. Selected request line(s): ${selectedLines.length}`
      );

      await loadNotifications();
      if (canViewEmailAdministration) await loadEmailLogs();

      const resultMessage = [
        `Notification Center records created: ${notificationCreated}`,
        `Emails sent: ${emailSent}`,
        emailSkipped ? `Emails skipped: ${emailSkipped}` : "",
        emailFailed ? `Emails failed: ${emailFailed}` : "",
        emailErrors.length ? `First email error: ${emailErrors[0]}` : "",
      ].filter(Boolean).join(" | ");

      setRequestAgencyNotificationMessage(resultMessage);
      alert(resultMessage);
    } catch (error) {
      setRequestAgencyNotificationMessage(`Agency notification failed: ${error.message}`);
      alert(error.message || "Agency notification failed.");
    } finally {
      setRequestAgencyNotificationSending(false);
    }
  }

  function addRequestLineToDraft() {
    if (!requestLineForm.profession || !requestLineForm.quantity) {
      return alert("Please fill Profession and Quantity for the request line.");
    }

    setRequestLinesDraft((prev) => [
      ...prev,
      {
        ...requestLineForm,
        quantity: Number(requestLineForm.quantity || 0),
        salary: requestLineForm.salary || "",
        interview_required: requestLineForm.interview_required || "Required",
        interview_type:
          requestLineForm.interview_required === "No Interview"
            ? "N/A"
            : requestLineForm.interview_type || "Online",
      },
    ]);

    setRequestLineForm(emptyRequestLine);
  }

  function removeRequestLineFromDraft(index) {
    setRequestLinesDraft((prev) => prev.filter((_, i) => i !== index));
  }

  function buildRequestLinesToSave() {
    const draftLines = requestLinesDraft.length > 0 ? requestLinesDraft : [];

    if (draftLines.length > 0) {
      return draftLines.map((line) => ({
        profession: line.profession || "",
        nationality: line.nationality || "",
        gender: line.gender || "",
        quantity: Number(line.quantity || 0),
        salary: line.salary || "",
        interview_required: line.interview_required || "Required",
        interview_type: line.interview_required === "No Interview" ? "N/A" : line.interview_type || "Online",
        notes: line.notes || "",
      }));
    }

    if (requestForm.profession && requestForm.quantity) {
      return [
        {
          profession: requestForm.profession || "",
          nationality: requestForm.nationality || "",
          gender: requestForm.gender || "",
          quantity: Number(requestForm.quantity || 0),
          salary: "",
          interview_required: requestForm.interview_required || "Required",
          interview_type:
            requestForm.interview_required === "No Interview"
              ? "N/A"
              : requestForm.interview_type || "Online",
          notes: requestForm.notes || "",
        },
      ];
    }

    return [];
  }

  function resetRequestForm() {
    setRequestForm(emptyRequest);
    setRequestLineForm(emptyRequestLine);
    setRequestLinesDraft([]);
    setRequestEditingId(null);
  }

  function editRequest(item) {
    const lines = getRequestLinesForRequest(item);

    setRequestEditingId(item.id);
    setRequestForm({
      recruitment_type: item.recruitment_type || (isSaudiNationality(item.nationality) ? "Saudi" : "Foreign"),
      request_type: item.request_type || "",
      request_date: item.request_date || "",
      project_name: item.project_name || "",
      project_no: item.project_no || "",
      project_city: item.project_city || "",
      project_location: item.project_location || "",
      department: item.department || "",
      profession: item.profession || lines[0]?.profession || "",
      quantity: item.quantity || lines[0]?.quantity || "",
      nationality: item.nationality || lines[0]?.nationality || "",
      gender: item.gender || lines[0]?.gender || "",
      salary: "",
      priority: item.priority || "Normal",
      status: item.status || "Open",
      requested_by: item.requested_by || "",
      project_start: item.project_start || "",
      interview_required: item.interview_required || lines[0]?.interview_required || "Required",
      interview_type: item.interview_type || lines[0]?.interview_type || "Online",
      notes: item.notes || "",
    });

    setRequestLinesDraft(
      lines.map((line) => ({
        profession: line.profession || "",
        nationality: line.nationality || "",
        gender: line.gender || "",
        quantity: Number(line.quantity || 0),
        salary: line.salary || "",
        interview_required: line.interview_required || "Required",
        interview_type: line.interview_type || "Online",
        notes: line.notes || "",
      }))
    );

    setActivePage("Requests");
    window.scrollTo({ top: 0, behavior: "smooth" });
  }

  async function saveRequest() {
    if (!canCreateRequest && !requestEditingId) return alert("You do not have permission to create requests.");
    if (!canEditRequest && requestEditingId) return alert("You do not have permission to edit requests.");

    const linesToSave = buildRequestLinesToSave();

    if (!requestForm.request_type || linesToSave.length === 0) {
      alert("Please fill Request Type and add at least one request line.");
      return;
    }

    const totalQuantity = linesToSave.reduce((sum, line) => sum + Number(line.quantity || 0), 0);
    const firstLine = linesToSave[0] || {};

    const payload = {
      ...requestForm,
      notes: requestForm.notes || "",
      profession: firstLine.profession || requestForm.profession || "",
      quantity: totalQuantity,
      nationality: firstLine.nationality || requestForm.nationality || "",
      gender: firstLine.gender || requestForm.gender || "",
      salary: firstLine.salary || "",
      interview_required: firstLine.interview_required || requestForm.interview_required || "Required",
      interview_type: firstLine.interview_type || requestForm.interview_type || "Online",
      request_date: requestForm.request_date || null,
      project_start: requestForm.project_start || null,
      request_no: requestEditingId ? undefined : "",
      approval_status: requestEditingId ? undefined : "Pending Recruitment Approval",
      request_status: requestEditingId ? undefined : "Draft",
      updated_at: new Date().toISOString(),
    };

    Object.keys(payload).forEach((key) => payload[key] === undefined && delete payload[key]);

    let result = null;

    if (requestEditingId) {
      result = await supabase
        .from("requests")
        .update(withUpdateActor(payload))
        .eq("id", requestEditingId)
        .select()
        .single();
    } else {
      // Retry a few times in case two users save at the same moment
      // or an old generated number already exists.
      let lastDuplicateError = null;

      for (let attempt = 1; attempt <= 7; attempt += 1) {
        const nextRequestNo = await generateRequestNo();
        const createPayload = {
          ...payload,
          request_no: nextRequestNo,
        };

        const insertResult = await supabase
          .from("requests")
          .insert([withCompany(withCreateActor(createPayload))])
          .select()
          .single();

        if (!insertResult.error) {
          result = insertResult;
          break;
        }

        if (!isDuplicateRequestNoError(insertResult.error)) {
          result = insertResult;
          break;
        }

        lastDuplicateError = insertResult.error;
        console.warn(`Duplicate request number ${nextRequestNo}. Retrying request save...`, insertResult.error.message);
      }

      if (!result) {
        result = {
          data: null,
          error: lastDuplicateError || { message: "Could not generate a unique request number. Please try again." },
        };
      }
    }

    if (result.error) {
      if (isDuplicateRequestNoError(result.error)) {
        return alert("Request number already exists. Please click Save Request again to generate the next available number.");
      }

      return alert(result.error.message);
    }

    const savedRequest = result.data;

    const deleteQuery = supabase
      .from("request_lines")
      .delete()
      .eq("company_id", currentCompanyId);

    const deleteResult = requestEditingId
      ? await deleteQuery.eq("request_id", savedRequest.id)
      : { error: null };

    if (deleteResult.error) return alert(`request_lines delete: ${deleteResult.error.message}`);

    const linePayload = linesToSave.map((line, index) =>
      withCompany(withCreateActor({
        request_id: savedRequest.id,
        request_no: savedRequest.request_no,
        line_no: index + 1,
        profession: line.profession || "",
        nationality: line.nationality || "",
        gender: line.gender || "",
        quantity: Number(line.quantity || 0),
        salary: line.salary || null,
        interview_required: line.interview_required || "Required",
        interview_type: line.interview_required === "No Interview" ? "N/A" : line.interview_type || "Online",
        notes: line.notes || "",
      }))
    );

    const lineResult = await supabase.from("request_lines").insert(linePayload);
    if (lineResult.error) return alert(`request_lines insert: ${lineResult.error.message}`);

    const wasEditingRequest = Boolean(requestEditingId);

    await addAudit(
      savedRequest.id,
      wasEditingRequest ? "Updated" : "Created",
      wasEditingRequest ? "Request header and lines were updated" : "Request header and lines were created"
    );

    const notificationLines = linesToSave.map((line, index) => ({
      ...line,
      request_id: savedRequest.id,
      request_no: savedRequest.request_no,
      line_no: index + 1,
      quantity: Number(line.quantity || 0),
    }));

    alert(
      wasEditingRequest
        ? "Request updated successfully. You can now select agencies and send notification."
        : `Request saved successfully: ${savedRequest.request_no}. You can now select agencies and send notification.`
    );

    resetRequestForm();
    await loadRequests();
    await loadRequestLines();

    if (canNotifyAgencies) {
      openRequestAgencyNotification(savedRequest, notificationLines);
    }
  }

