async function convertCandidateToEmployee(candidate) {
  if (!canManageEmployees) return alert("You do not have permission to create employees.");
  if (!candidate) return alert("Candidate not found.");

  const existing = employees.find(
    (employee) => String(employee.source_candidate_id || "") === String(candidate.id || "")
  );

  if (existing) {
    return alert(`This candidate is already converted to employee: ${existing.employee_no}`);
  }

  const employeeNo = await generateEmployeeNo();
  const payload = {
    employee_no: employeeNo,
    employee_name: candidate.candidate_name || "",
    iqama_no: "",
    nationality: candidate.nationality || "",
    gender: candidate.gender || "",
    profession: candidate.profession || "",
    project_name: candidate.project || "",
    department: "",
    joining_date: candidate.joining_date || candidate.arrival_date || new Date().toISOString().slice(0, 10),
    contract_end_date: null,
    status: "Active",
    source_candidate_id: Number(candidate.id || 0) || null,
    notes: `Converted from candidate ${candidate.candidate_name || ""} / Request ${candidate.request_no || "-"}`,
    updated_at: new Date().toISOString(),
  };

  const result = await supabase.from("employees").insert([withCompany(payload)]);
  if (result.error) return alert(result.error.message);

  await supabase
    .from("candidates")
    .update(withUpdateActor({ status: "Joined", updated_at: new Date().toISOString() }))
    .eq("id", candidate.id)
    .eq("company_id", currentCompanyId);

  alert(`Candidate converted to employee: ${employeeNo}`);
  await loadEmployees();
  await loadCandidates();
  setActivePage("Employees");
}

const employeeIntelligence = useMemo(() => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const next60 = new Date(today);
  next60.setDate(next60.getDate() + 60);

  const activeEmployees = employees.filter((employee) => employee.status === "Active");
  const expiringSoon = activeEmployees.filter((employee) => {
    if (!employee.contract_end_date) return false;
    const endDate = new Date(employee.contract_end_date);
    return endDate >= today && endDate <= next60;
  });

  const openRequests = requests.filter((request) =>
    ["Open", "Under Recruitment", "Interview Stage", "Visa Process"].includes(request.status || "Open")
  );

  let redeploymentMatches = 0;
  expiringSoon.forEach((employee) => {
    const hasMatch = openRequests.some(
      (request) =>
        normalize(request.profession) === normalize(employee.profession) &&
        (!request.nationality || !employee.nationality || normalize(request.nationality) === normalize(employee.nationality)) &&
        (!request.gender || !employee.gender || normalize(request.gender) === normalize(employee.gender))
    );
    if (hasMatch) redeploymentMatches += 1;
  });

  const potentialSaving = redeploymentMatches * 3150;

  const projectRisk = Object.values(
    expiringSoon.reduce((acc, employee) => {
      const key = employee.project_name || "Unassigned";
      if (!acc[key]) acc[key] = { project: key, count: 0, professions: new Set() };
      acc[key].count += 1;
      if (employee.profession) acc[key].professions.add(employee.profession);
      return acc;
    }, {})
  )
    .map((item) => ({ ...item, professions: Array.from(item.professions).join(", ") }))
    .sort((a, b) => b.count - a.count)[0] || null;

  return {
    totalEmployees: employees.length,
    activeEmployees: activeEmployees.length,
    expiringSoon: expiringSoon.length,
    redeploymentMatches,
    potentialSaving,
    projectRisk,
  };
}, [employees, requests]);


function getNumericPercent(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function getEmployeeMonthlySalary(employee) {
  return Number(employee?.salary || employee?.basic_salary || employee?.monthly_salary || employee?.total_salary || 0);
}

function getDaysUntil(dateValue, fromDate = new Date()) {
  if (!dateValue) return null;
  const start = new Date(fromDate);
  start.setHours(0, 0, 0, 0);
  const end = new Date(dateValue);
  if (Number.isNaN(end.getTime())) return null;
  end.setHours(0, 0, 0, 0);
  return Math.ceil((end - start) / (1000 * 60 * 60 * 24));
}

function getProjectTarget(projectName) {
  const target = localContentProjectTargets.find((item) => normalize(item.project_name) === normalize(projectName));
  return {
    project_name: projectName || "Unassigned",
    project_city: target?.project_city || "",
    project_location: target?.project_location || "",
    target_percent: getNumericPercent(target?.target_percent, localContentSettings.default_target_percent),
    monthly_invoice_amount: Number(target?.monthly_invoice_amount || 0),
    penalty_percent: getNumericPercent(target?.penalty_percent, localContentSettings.default_monthly_penalty_percent),
    notes: target?.notes || "",
    id: target?.id || null,
  };
}

function calculateLocalContentForEmployees(rows = []) {
  const activeRows = rows.filter((employee) => String(employee.status || "Active").toLowerCase() !== "final exit");
  const saudiRows = activeRows.filter((employee) => isSaudiNationality(employee.nationality));
  const nonSaudiRows = activeRows.filter((employee) => !isSaudiNationality(employee.nationality));
  const saudiPayroll = saudiRows.reduce((sum, employee) => sum + getEmployeeMonthlySalary(employee), 0);
  const nonSaudiPayroll = nonSaudiRows.reduce((sum, employee) => sum + getEmployeeMonthlySalary(employee), 0);
  const totalPayroll = saudiPayroll + nonSaudiPayroll;
  const localWorkforceValue =
    saudiPayroll * (getNumericPercent(localContentSettings.saudi_labor_weight, 100) / 100) +
    nonSaudiPayroll * (getNumericPercent(localContentSettings.non_saudi_labor_weight, 54) / 100);
  const headcount = activeRows.length;
  const saudiHeadcount = saudiRows.length;
  const saudizationPercent = headcount ? Math.round((saudiHeadcount / headcount) * 10000) / 100 : 0;
  const workforceLocalContentPercent = totalPayroll ? Math.round((localWorkforceValue / totalPayroll) * 10000) / 100 : 0;

  return {
    headcount,
    saudiHeadcount,
    nonSaudiHeadcount: nonSaudiRows.length,
    saudiPayroll,
    nonSaudiPayroll,
    totalPayroll,
    localWorkforceValue,
    saudizationPercent,
    workforceLocalContentPercent,
  };
}

const localContentDashboard = useMemo(() => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const forecastDays = Number(localContentSettings.forecast_days || 90);
  const expiringWindowDays = Number(localContentSettings.expiring_window_days || 60);

  const activeEmployees = employees.filter((employee) =>
    !["Final Exit", "Transferred"].includes(String(employee.status || "Active"))
  );

  const projectMap = new Map();
  activeEmployees.forEach((employee) => {
    const projectName = employee.project_name || "Unassigned";
    if (!projectMap.has(projectName)) projectMap.set(projectName, []);
    projectMap.get(projectName).push(employee);
  });

  const projectRows = Array.from(projectMap.entries()).map(([projectName, rows]) => {
    const target = getProjectTarget(projectName);
    const relatedRequest = requests.find((request) => normalize(request.project_name || request.project || "Unassigned") === normalize(projectName));
    const projectCity = target.project_city || rows.find((employee) => employee.project_city)?.project_city || relatedRequest?.project_city || "";
    const projectLocation = target.project_location || rows.find((employee) => employee.project_location)?.project_location || relatedRequest?.project_location || "";
    const current = calculateLocalContentForEmployees(rows);
    const forecastRows = rows.filter((employee) => {
      const days = getDaysUntil(employee.contract_end_date, today);
      return !(isSaudiNationality(employee.nationality) && days !== null && days >= 0 && days <= forecastDays);
    });
    const forecast = calculateLocalContentForEmployees(forecastRows);
    const expiringSaudi = rows.filter((employee) => {
      const days = getDaysUntil(employee.contract_end_date, today);
      return isSaudiNationality(employee.nationality) && days !== null && days >= 0 && days <= forecastDays;
    });
    const gap = Math.max(target.target_percent - current.saudizationPercent, 0);
    const forecastGap = Math.max(target.target_percent - forecast.saudizationPercent, 0);
    const neededSaudiNow = Math.ceil((gap / 100) * Math.max(current.headcount, 1));
    const neededSaudiForecast = Math.ceil((forecastGap / 100) * Math.max(forecast.headcount, 1));
    const expectedPenalty = target.monthly_invoice_amount && target.penalty_percent && forecastGap > 0
      ? Math.round(target.monthly_invoice_amount * (target.penalty_percent / 100))
      : 0;
    const riskLevel = forecastGap >= 10 || expectedPenalty > 0
      ? "High"
      : forecastGap > 0 || expiringSaudi.length > 0
        ? "Medium"
        : "Low";

    return {
      projectName,
      projectCity,
      projectLocation,
      ...current,
      targetPercent: target.target_percent,
      forecastSaudizationPercent: forecast.saudizationPercent,
      expiringSaudiCount: expiringSaudi.length,
      gap,
      forecastGap,
      neededSaudiNow,
      neededSaudiForecast,
      monthlyInvoiceAmount: target.monthly_invoice_amount,
      penaltyPercent: target.penalty_percent,
      expectedPenalty,
      riskLevel,
      notes: target.notes,
    };
  }).sort((a, b) => {
    const order = { High: 0, Medium: 1, Low: 2 };
    return (order[a.riskLevel] ?? 9) - (order[b.riskLevel] ?? 9) || b.forecastGap - a.forecastGap;
  });

  const company = calculateLocalContentForEmployees(activeEmployees);
  const companyTarget = Number(localContentSettings.default_target_percent || 35);
  const highRiskProjects = projectRows.filter((row) => row.riskLevel === "High").length;
  const mediumRiskProjects = projectRows.filter((row) => row.riskLevel === "Medium").length;
  const forecastExpiringSaudi = projectRows.reduce((sum, row) => sum + Number(row.expiringSaudiCount || 0), 0);
  const expectedPenalty = projectRows.reduce((sum, row) => sum + Number(row.expectedPenalty || 0), 0);

  const riskyProjects = projectRows.filter((row) => row.forecastGap > 0 || row.gap > 0);
  const transferableEmployees = activeEmployees.filter((employee) => {
    const status = String(employee.status || "Active").toLowerCase();
    if (!["active", "available"].includes(status)) return false;
    if (!employee.profession) return false;
    return true;
  });

  const blockedCandidateStatuses = ["Rejected", "Interview Failed", "Medical Failed", "Cancelled", "KSA Medical Failed", "Refused to Work", "Absconded"];

  function getFilledDemandQty(request, line) {
    const qtyField = Number(line?.quantity || request?.quantity || 0);
    return candidates.filter((candidate) => {
      if (String(candidate.request_no || "") !== String(request.request_no || "")) return false;
      if (blockedCandidateStatuses.includes(candidate.status)) return false;

      if (line?.id && !String(line.id).includes("legacy")) {
        return String(candidate.request_line_id || "") === String(line.id || "") || (
          isUnifiedProfessionMatch(candidate.profession, line.profession) &&
          (isAnyValue(line.nationality) || isAnyValue(candidate.nationality) || normalizeMatchText(candidate.nationality) === normalizeMatchText(line.nationality)) &&
          (isAnyValue(line.gender) || isAnyValue(candidate.gender) || normalize(candidate.gender) === normalize(line.gender))
        );
      }

      return (
        isUnifiedProfessionMatch(candidate.profession, line?.profession || request.profession) &&
        (isAnyValue(line?.nationality || request.nationality) || isAnyValue(candidate.nationality) || normalizeMatchText(candidate.nationality) === normalizeMatchText(line?.nationality || request.nationality)) &&
        (isAnyValue(line?.gender || request.gender) || isAnyValue(candidate.gender) || normalize(candidate.gender) === normalize(line?.gender || request.gender))
      );
    }).slice(0, qtyField || undefined).length;
  }

  function employeeMatchesDemand(employee, demand) {
    if (!isUnifiedProfessionMatch(employee.profession, demand.profession)) return false;

    const demandNationality = demand.nationality;
    const employeeNationality = employee.nationality;
    const demandGender = demand.gender;
    const employeeGender = employee.gender;

    const nationalityMatches = isAnyValue(demandNationality) || isAnyValue(employeeNationality) ||
      (isSaudiNationality(demandNationality) && isSaudiNationality(employeeNationality)) ||
      normalizeMatchText(demandNationality) === normalizeMatchText(employeeNationality);

    const genderMatches = isAnyValue(demandGender) || isAnyValue(employeeGender) || normalize(demandGender) === normalize(employeeGender);

    return nationalityMatches && genderMatches;
  }

  const openDemandRows = requests.flatMap((request) => {
    const status = request.status || "Open";
    if (!["Open", "Under Recruitment", "Interview Stage", "Visa Process"].includes(status)) return [];
    if (["Rejected by Recruitment", "Cancelled"].includes(request.approval_status)) return [];

    const projectName = request.project_name || request.project || "Unassigned";
    const lines = getRequestLinesForRequest(request);

    return lines.map((line) => {
      const requiredQty = Number(line.quantity || request.quantity || 0);
      const filledQty = getFilledDemandQty(request, line);
      const remainingQty = Math.max(requiredQty - filledQty, 0);
      return {
        request,
        line,
        projectName,
        projectCity: request.project_city || "",
        projectLocation: request.project_location || "",
        profession: line.profession || request.profession || "",
        nationality: line.nationality || request.nationality || "",
        gender: line.gender || request.gender || "",
        requiredQty,
        filledQty,
        remainingQty,
      };
    }).filter((demand) => demand.remainingQty > 0 && demand.profession);
  });

  const transferSuggestions = transferableEmployees.flatMap((employee) => {
    const sourceProject = employee.project_name || "Unassigned";
    const daysToEnd = getDaysUntil(employee.contract_end_date, today);

    return openDemandRows
      .filter((demand) => normalize(demand.projectName) !== normalize(sourceProject))
      .filter((demand) => employeeMatchesDemand(employee, demand))
      .slice(0, 5)
      .map((demand) => {
        const targetProject = projectRows.find((row) => normalize(row.projectName) === normalize(demand.projectName)) || null;
        const isSaudi = isSaudiNationality(employee.nationality);
        const timingScore = daysToEnd !== null && daysToEnd <= expiringWindowDays ? 20 : 8;
        const cityScore = employee.project_city && demand.projectCity && normalize(employee.project_city) === normalize(demand.projectCity) ? 10 : 0;
        const demandScore = Math.min(35, 20 + Math.min(demand.remainingQty, 15));
        const professionScore = 35;
        const score = Math.min(100, professionScore + demandScore + timingScore + cityScore);

        return {
          employee_id: employee.id,
          employee_no: employee.employee_no || "-",
          employee_name: employee.employee_name || "-",
          employee_type: isSaudi ? "Saudi" : "Expat",
          profession: employee.profession || "-",
          nationality: employee.nationality || "-",
          gender: employee.gender || "-",
          source_project: sourceProject,
          target_project: demand.projectName,
          target_city: targetProject?.projectCity || demand.projectCity || "",
          target_location: targetProject?.projectLocation || demand.projectLocation || "",
          request_no: demand.request.request_no || "-",
          demand_profession: demand.profession,
          demand_nationality: demand.nationality || "Any",
          demand_gender: demand.gender || "Any",
          remaining_demand_qty: demand.remainingQty,
          days_to_contract_end: daysToEnd,
          salary: getEmployeeMonthlySalary(employee),
          match_score: score,
          reason: `Matching open demand ${demand.request.request_no || ""}: ${demand.profession}${demand.nationality ? ` / ${demand.nationality}` : ""}${demand.gender ? ` / ${demand.gender}` : ""}. Suggested for Operations review only.`,
        };
      });
  })
    .sort((a, b) => b.match_score - a.match_score)
    .filter((item, index, arr) => arr.findIndex((x) => String(x.employee_id) === String(item.employee_id) && x.request_no === item.request_no) === index)
    .slice(0, 30);


  const selectedProjects = localContentSelectedProject === "All"
    ? projectRows
    : projectRows.filter((row) => row.projectName === localContentSelectedProject);

  return {
    company,
    companyTarget,
    projectRows,
    selectedProjects,
    highRiskProjects,
    mediumRiskProjects,
    forecastExpiringSaudi,
    expectedPenalty,
    transferSuggestions,
  };
}, [employees, requests, requestLines, candidates, professions, professionAliases, localContentSettings, localContentProjectTargets, localContentSelectedProject]);

