async function handleChangePasswordSubmit() {
  const currentPassword = String(changePasswordForm.current_password || "").trim();
  const newPassword = String(changePasswordForm.new_password || "").trim();
  const confirmPassword = String(changePasswordForm.confirm_password || "").trim();

  if (!currentUser?.id || !currentUser?.email) {
    setChangePasswordMessage("Login session is missing. Please logout and login again.");
    return;
  }

  if (!currentPassword || !newPassword || !confirmPassword) {
    setChangePasswordMessage("Please fill current password, new password, and confirmation.");
    return;
  }

  if (newPassword.length < 8) {
    setChangePasswordMessage("New password must be at least 8 characters.");
    return;
  }

  if (newPassword !== confirmPassword) {
    setChangePasswordMessage("New password and confirmation do not match.");
    return;
  }

  if (currentPassword === newPassword) {
    setChangePasswordMessage("New password must be different from the current password.");
    return;
  }

  setChangePasswordLoading(true);
  setChangePasswordMessage("");

  try {
    if (currentUser.auth_user_id) {
      const { error: verifyError } = await supabase.auth.signInWithPassword({
        email: String(currentUser.email || "").trim().toLowerCase(),
        password: currentPassword,
      });

      if (verifyError) {
        throw new Error("Current password is incorrect.");
      }

      const { error: updateError } = await supabase.auth.updateUser({
        password: newPassword,
      });

      if (updateError) throw updateError;
    } else {
      const { data: legacyUser, error: legacyError } = await supabase
        .from("users")
        .select("id")
        .eq("id", currentUser.id)
        .eq("email", currentUser.email)
        .eq("password", currentPassword)
        .maybeSingle();

      if (legacyError) throw legacyError;
      if (!legacyUser) throw new Error("Current password is incorrect.");

      const { error: updateError } = await supabase
        .from("users")
        .update({ password: newPassword })
        .eq("id", currentUser.id)
        .eq("email", currentUser.email);

      if (updateError) throw updateError;
    }

    setChangePasswordForm({
      current_password: "",
      new_password: "",
      confirm_password: "",
    });
    setChangePasswordMessage("Password changed successfully. Please use the new password next time you login.");
  } catch (error) {
    setChangePasswordMessage(error?.message || "Unable to change password.");
  } finally {
    setChangePasswordLoading(false);
  }
}

async function handleLogin() {
  const email = loginForm.email.trim().toLowerCase();
  const password = loginForm.password.trim();

  if (!email || !password) {
    alert("Please enter email and password");
    return;
  }

  setLoginLoading(true);
  resetUserEditingState();

  try {
    // Migration-safe login:
    // 1) If the user is already linked to Supabase Auth, require Supabase Auth password.
    // 2) If the user is not linked yet, keep the old custom login temporarily.
    const { data: existingUser, error: existingUserError } = await supabase
      .from("users")
      .select("id, email, role, auth_user_id")
      .eq("email", email)
      .maybeSingle();

    if (existingUserError) {
      console.warn("Login user lookup failed:", existingUserError.message);
      alert("Login failed. Please try again.");
      return;
    }

    if (!existingUser) {
      alert("Invalid email or password");
      return;
    }

    // Security: platform roles must never use the temporary legacy-password fallback.
    // This prevents any company Admin from creating a legacy Platform user and entering the owner area.
    if (!existingUser.auth_user_id && isPlatformRole(existingUser.role)) {
      alert("Platform users must login through secure Supabase Auth. Please contact the platform owner.");
      return;
    }

    let userData = null;

    if (existingUser.auth_user_id) {
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (authError || !authData?.user?.id) {
        console.warn("Supabase Auth login failed:", authError?.message || authError);
        alert("Invalid email or password");
        return;
      }

      const { data: linkedUser, error: linkedUserError } = await supabase
        .from("users")
        .select("id, name, email, role, agency_id, agency_name, status, is_active, company_id, auth_user_id")
        .eq("auth_user_id", authData.user.id)
        .maybeSingle();

      if (linkedUserError || !linkedUser) {
        await supabase.auth.signOut();
        alert("This authenticated account is not linked to a VisaFlow user.");
        return;
      }

      userData = linkedUser;
    } else {
      const { data: legacyUser, error: legacyUserError } = await supabase
        .from("users")
        .select("id, name, email, role, agency_id, agency_name, status, is_active, company_id, auth_user_id")
        .eq("email", email)
        .eq("password", password)
        .maybeSingle();

      if (legacyUserError || !legacyUser) {
        alert("Invalid email or password");
        return;
      }

      if (isPlatformRole(legacyUser.role)) {
        alert("Platform users must login through secure Supabase Auth. Please contact the platform owner.");
        return;
      }

      userData = legacyUser;
    }

    if (isPlatformRole(userData?.role) && !userData?.auth_user_id) {
      alert("Platform users must be linked to Supabase Auth before login.");
      return;
    }

    const userStatus = String(userData.status || "").trim().toLowerCase();
    if (userStatus !== "active" || userData.is_active === false) {
      alert("This user is not active");
      return;
    }

    let companyData = null;

    if (userData.company_id) {
      const { data: company, error: companyError } = await supabase
        .from("companies")
        .select("id, name, status, subscription_status, subscription_end")
        .eq("id", userData.company_id)
        .maybeSingle();

      if (companyError) {
        console.warn("Company check failed:", companyError.message);
      }

      companyData = company;

      const companyStatus = String(companyData?.status || "").trim().toLowerCase();
      const subscriptionStatus = String(companyData?.subscription_status || "").trim().toLowerCase();

      console.log("Company Check:", {
        userCompanyId: userData.company_id,
        companyData,
        companyStatus,
        subscriptionStatus,
      });

      // Important:
      // If companyData is null, the frontend likely cannot read the companies table
      // because of RLS / policy settings. Do not block login in this case.
      // The user's company_id will still isolate all operational data through currentCompanyId.
      if (companyData) {
        if (companyStatus !== "active" || !isLoginAllowedSubscriptionStatus(subscriptionStatus)) {
          alert("Company subscription is not active. Please contact the system administrator.");
          return;
        }

        if (companyData.subscription_end) {
          const endDate = new Date(companyData.subscription_end);
          endDate.setHours(23, 59, 59, 999);
          if (endDate < new Date()) {
            alert("Company subscription has expired. Please contact the system administrator.");
            return;
          }
        }
      }
    }

    const loggedUser = {
      ...userData,
      role: normalizeUserRole(userData.role),
      company_name: companyData?.name || userData.company_name || "",
      subscription_status: companyData?.subscription_status || "",
    };

    if (loggedUser.role === "Agency") {
      const workspaces = await loadAgencyClientAccess(loggedUser, false);
      const storedCompanyId = sessionStorage.getItem("visaflow_agency_company_id") || "";
      const selectedWorkspace =
        workspaces.find((item) => String(item.company_id) === String(storedCompanyId)) ||
        workspaces.find((item) => String(item.company_id) === String(loggedUser.company_id || "")) ||
        workspaces[0] ||
        null;

      if (selectedWorkspace) {
        loggedUser.active_company_id = selectedWorkspace.company_id;
        loggedUser.active_company_name = selectedWorkspace.company_name || "Client Workspace";
        sessionStorage.setItem("visaflow_agency_company_id", String(selectedWorkspace.company_id));
        sessionStorage.setItem("visaflow_agency_company_name", loggedUser.active_company_name);
        setActiveAgencyCompanyId(String(selectedWorkspace.company_id));
        setActiveAgencyCompanyName(loggedUser.active_company_name);
      } else if (!loggedUser.company_id) {
        alert("No active client workspace is assigned to this agency user. Please contact the platform administrator.");
        return;
      }
    }

    const storage = rememberMe ? localStorage : sessionStorage;
    localStorage.removeItem("visaflow_user");
    sessionStorage.removeItem("visaflow_user");
    storage.setItem("visaflow_user", JSON.stringify(loggedUser));

    try {
      await supabase
        .from("users")
        .update({ last_login: new Date().toISOString() })
        .eq("id", loggedUser.id);
    } catch (lastLoginError) {
      console.warn("last_login update failed", lastLoginError?.message || lastLoginError);
    }

    setCurrentUser(loggedUser);
    setActivePage((ROLE_PAGES[loggedUser.role] || ROLE_PAGES.Viewer)[0]);
  } finally {
    setLoginLoading(false);
  }
}

async function handleLogout() {
  try {
    await supabase.auth.signOut();
  } catch (error) {
    console.warn("Supabase sign out failed", error?.message || error);
  }

  localStorage.removeItem("visaflow_user");
  sessionStorage.removeItem("visaflow_user");
  sessionStorage.removeItem("visaflow_agency_company_id");
  sessionStorage.removeItem("visaflow_agency_company_name");
  setAgencyClientAccess([]);
  setActiveAgencyCompanyId("");
  setActiveAgencyCompanyName("");
  setCurrentUser(null);
  resetUserEditingState();
  setLoginForm({ email: "", password: "" });
  setChangePasswordOpen(false);
  resetChangePasswordForm();
  setActivePage("Dashboard");
}


function exportRowsToExcel(rows, fileName, sheetName = "Data") {
  if (!rows || rows.length === 0) {
    alert("No data to export");
    return;
  }

  const cleanRows = rows.map((row) => {
    const clean = {};
    Object.entries(row).forEach(([key, value]) => {
      if (typeof value !== "object") clean[key] = value ?? "";
    });
    return clean;
  });

  const worksheet = XLSX.utils.json_to_sheet(cleanRows);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, sheetName);
  XLSX.writeFile(workbook, `${fileName}.xlsx`);
}

function executiveAlertClass(value) {
  const number = Number(value || 0);
  if (number === 0) return "passed";
  if (number <= 5) return "warning";
  return "danger";
}


function getAgencyAssignedWorkProfile(agencyName = "") {
  const normalizedAgency = normalize(agencyName);

  const emptyProfile = {
    agencyCandidates: [],
    agencyInterviews: [],
    agencyAuthorizations: [],
    activeAuthorizations: [],
    acceptedRequestAlerts: [],
    activeRequestNos: [],
    authorizedQty: 0,
    hasCandidateActivity: false,
    hasActiveAuthorization: false,
    hasAcceptedRequestAlert: false,
    hasAssignedWork: false,
    performanceStatus: "No Assigned Work",
  };

  if (!normalizedAgency) return emptyProfile;

  const agencyCandidates = candidates.filter((candidate) => normalize(candidate.agency) === normalizedAgency);
  const agencyInterviews = interviews.filter((interview) => normalize(interview.agency) === normalizedAgency);
  const agencyAuthorizations = visaAuthorizations.filter((authorization) => normalize(authorization.agency) === normalizedAgency);
  const activeAuthorizations = agencyAuthorizations.filter((authorization) => {
    const status = normalize(authorization.status || "Open");
    return !["cancelled", "canceled", "closed", "completed"].includes(status);
  });

  const acceptedRequestAlerts = (notifications || []).filter((item) => {
    const data = getAgencyNotificationPayload(item);
    const notificationType = String(item?.type || data.type || "").trim();
    const isAgencyRequestAlert = ["NEW_REQUEST_AGENCY_ALERT", "AGENCY_REQUEST_NOTIFICATION"].includes(notificationType);
    const agencyMatches = normalize(getAgencyNotificationAgencyName(item)) === normalizedAgency;
    const response = normalize(getAgencyNotificationResponseStatus(item));

    return isAgencyRequestAlert && agencyMatches && ["accepted", "accept"].includes(response);
  });

  const authorizedQty = activeAuthorizations.reduce((sum, authorization) => sum + Number(authorization.allocated_qty || 0), 0);
  const hasCandidateActivity = agencyCandidates.length > 0 || agencyInterviews.length > 0;
  const hasActiveAuthorization = activeAuthorizations.some(
    (authorization) =>
      Number(authorization.allocated_qty || 0) > 0 ||
      Boolean(authorization.request_no) ||
      Boolean(authorization.authorization_no) ||
      Boolean(authorization.visa_no)
  );
  const hasAcceptedRequestAlert = acceptedRequestAlerts.length > 0;
  const hasAssignedWork = hasCandidateActivity || hasActiveAuthorization || hasAcceptedRequestAlert;

  const activeRequestNos = Array.from(
    new Set([
      ...agencyCandidates.map((candidate) => candidate.request_no),
      ...activeAuthorizations.map((authorization) => authorization.request_no),
      ...acceptedRequestAlerts.map((alert) => getAgencyNotificationRequestNo(alert)),
    ].map((value) => String(value || "").trim()).filter((value) => value && value !== "-"))
  );

  return {
    agencyCandidates,
    agencyInterviews,
    agencyAuthorizations,
    activeAuthorizations,
    acceptedRequestAlerts,
    activeRequestNos,
    authorizedQty,
    hasCandidateActivity,
    hasActiveAuthorization,
    hasAcceptedRequestAlert,
    hasAssignedWork,
    performanceStatus: hasAssignedWork ? "Active Assignment" : "No Assigned Work",
  };
}


function buildAgencyAssignedWorkRows() {
  const agencyNames = Array.from(
    new Set([
      ...agencies.map((agency) => agency.name).filter(Boolean),
      ...candidates.map((candidate) => candidate.agency).filter(Boolean),
      ...visaAuthorizations.map((authorization) => authorization.agency).filter(Boolean),
      ...notifications.map((item) => getAgencyNotificationAgencyName(item)).filter(Boolean),
    ])
  );

  const finalCandidateStatuses = [
    "Joined",
    "Rejected",
    "Interview Failed",
    "Medical Failed",
    "Cancelled",
    "KSA Medical Failed",
    "Refused to Work",
    "Absconded",
  ];

  return agencyNames
    .map((agencyName) => {
      const agency = agencies.find((item) => normalize(item.name) === normalize(agencyName));
      const workProfile = getAgencyAssignedWorkProfile(agencyName);
      const {
        agencyCandidates,
        agencyInterviews,
        activeAuthorizations,
        acceptedRequestAlerts,
        activeRequestNos,
        authorizedQty,
        hasAssignedWork,
        performanceStatus,
      } = workProfile;

      const requestDetails = activeRequestNos.map((requestNo) => {
        const request = requests.find((item) => String(item.request_no || "") === String(requestNo || ""));
        const requestCandidates = agencyCandidates.filter((candidate) => String(candidate.request_no || "") === String(requestNo || ""));
        const requestAuthorizations = activeAuthorizations.filter((authorization) => String(authorization.request_no || "") === String(requestNo || ""));
        const requestAuthQty = requestAuthorizations.reduce((sum, authorization) => sum + Number(authorization.allocated_qty || 0), 0);
        const joinedCount = requestCandidates.filter((candidate) => candidate.status === "Joined").length;
        const openCandidateCount = requestCandidates.filter((candidate) => !finalCandidateStatuses.includes(candidate.status)).length;
        const lines = request ? getRequestLinesForRequest(request) : [];
        const lineSummary = lines.length
          ? lines.map((line) => `${line.profession || "-"}/${line.nationality || "-"}/${line.gender || "-"} Qty ${Number(line.quantity || 0)}`).join("; ")
          : [request?.profession, request?.nationality, request?.gender].filter(Boolean).join(" / ") || "No request line details";

        return [
          requestNo,
          request?.project_name || request?.project || "No project",
          lineSummary,
          `Auth Qty: ${requestAuthQty}`,
          `Candidates: ${requestCandidates.length}`,
          `Open: ${openCandidateCount}`,
          `Joined: ${joinedCount}`,
        ].join(" | ");
      });

      const latestUpdate = [
        ...agencyCandidates.map((candidate) => candidate.updated_at || candidate.created_at),
        ...activeAuthorizations.map((authorization) => authorization.updated_at || authorization.created_at),
        ...acceptedRequestAlerts.map((item) => item.response_at || item.created_at),
      ]
        .filter(Boolean)
        .sort((a, b) => new Date(b) - new Date(a))[0] || "";

      const openCandidates = agencyCandidates.filter((candidate) => !finalCandidateStatuses.includes(candidate.status)).length;
      const joined = agencyCandidates.filter((candidate) => candidate.status === "Joined").length;
      const delayed = agencyCandidates.filter((candidate) => getCandidateSlaDelay(candidate, agencyName).isDelayed).length;

      return {
        agency_id: agency?.id || null,
        agency_name: agencyName,
        country: agency?.country || agency?.office_country || "-",
        performanceStatus,
        hasAssignedWork,
        request_count: activeRequestNos.length,
        request_nos: activeRequestNos.join(", ") || "-",
        authorizations: activeAuthorizations.length,
        authorizedQty,
        acceptedRequests: acceptedRequestAlerts.length,
        candidates: agencyCandidates.length,
        openCandidates,
        interviews: agencyInterviews.length,
        joined,
        delayed,
        latestUpdate,
        workDetails: requestDetails.length ? requestDetails.join("\n") : "No active request, authorization, candidate, or accepted sourcing alert assigned.",
      };
    })
    .sort((a, b) => {
      const assignedDiff = Number(b.hasAssignedWork) - Number(a.hasAssignedWork);
      if (assignedDiff) return assignedDiff;
      return String(a.agency_name || "").localeCompare(String(b.agency_name || ""));
    });
}

function isAgencyScorecardRiskItem(row = {}) {
  return Boolean(row?.hasAssignedWork) && ["High", "Medium"].includes(row?.risk);
}

function buildAgencyScorecard() {
  const agencyNames = Array.from(
    new Set([
      ...agencies.map((agency) => agency.name).filter(Boolean),
      ...candidates.map((candidate) => candidate.agency).filter(Boolean),
      ...visaAuthorizations.map((authorization) => authorization.agency).filter(Boolean),
    ])
  );

  return agencyNames
    .map((agencyName) => {
      const workProfile = getAgencyAssignedWorkProfile(agencyName);
      const {
        agencyCandidates,
        agencyInterviews,
        activeAuthorizations,
        acceptedRequestAlerts,
        activeRequestNos,
        authorizedQty,
        hasAssignedWork,
        performanceStatus,
      } = workProfile;

      if (!hasAssignedWork) {
        return {
          agency: agencyName,
          candidates: 0,
          authorizedQty: 0,
          assignedRequests: 0,
          acceptedRequests: 0,
          submittedPercent: null,
          passedInterviews: 0,
          rejectedInterviews: 0,
          arrived: 0,
          joined: 0,
          failed: 0,
          successRate: null,
          failRate: null,
          score: null,
          risk: "N/A",
          hasAssignedWork: false,
          performanceStatus,
          activeRequestNos: [],
          recommendation: "No active assignment. Do not calculate score or send performance follow-up.",
        };
      }

      const passedInterviews = agencyInterviews.filter((interview) => interview.status === "Passed").length;
      const rejectedInterviews = agencyInterviews.filter((interview) => ["Rejected", "Interview Failed"].includes(interview.status)).length;
      const joinedCandidates = agencyCandidates.filter((candidate) => candidate.status === "Joined").length;
      const arrivedCandidates = agencyCandidates.filter((candidate) => ["Arrived KSA", "Arrived", "Joined"].includes(candidate.status)).length;
      const failedCandidates = agencyCandidates.filter((candidate) =>
        ["Rejected", "Interview Failed", "Medical Failed", "Cancelled", "KSA Medical Failed", "Refused to Work", "Absconded"].includes(candidate.status)
      ).length;
      const submissionRate = authorizedQty ? Math.round((agencyCandidates.length / authorizedQty) * 100) : agencyCandidates.length ? 100 : 0;
      const successRate = agencyCandidates.length ? Math.round(((joinedCandidates + arrivedCandidates) / agencyCandidates.length) * 100) : 0;
      const failRate = agencyCandidates.length ? Math.round((failedCandidates / agencyCandidates.length) * 100) : 0;
      const interviewPassRate = agencyInterviews.length ? Math.round((passedInterviews / agencyInterviews.length) * 100) : 0;

      const score = Math.max(
        0,
        Math.min(
          100,
          Math.round(
            successRate * 0.35 +
              interviewPassRate * 0.25 +
              Math.min(submissionRate, 100) * 0.25 -
              failRate * 0.15 +
              Math.min(agencyCandidates.length, 20)
          )
        )
      );

      let risk = "Low";
      if (score < 45 || failRate >= 35) risk = "High";
      else if (score < 70 || submissionRate < 50) risk = "Medium";

      return {
        agency: agencyName,
        candidates: agencyCandidates.length,
        authorizedQty,
        assignedRequests: activeRequestNos.length,
        acceptedRequests: acceptedRequestAlerts.length,
        submittedPercent: submissionRate,
        passedInterviews,
        rejectedInterviews,
        arrived: arrivedCandidates,
        joined: joinedCandidates,
        failed: failedCandidates,
        successRate,
        failRate,
        score,
        risk,
        hasAssignedWork: true,
        performanceStatus,
        activeRequestNos,
      };
    })
    .sort((a, b) => {
      const assignedDiff = Number(b.hasAssignedWork) - Number(a.hasAssignedWork);
      if (assignedDiff) return assignedDiff;
      return Number(b.score || 0) - Number(a.score || 0);
    });
}

function getAgencyRank(totalScore) {
  const score = Number(totalScore || 0);
  if (score >= 95) return "Platinum";
  if (score >= 85) return "Gold";
  if (score >= 70) return "Silver";
  return "Under Review";
}



function getActiveAgencyAgreement(agencyName) {
  const now = new Date();
  return [...agencyAgreements]
    .filter((agreement) => {
      const status = String(agreement.status || "").trim().toLowerCase();
      const nameMatches = normalize(agreement.agency_name) === normalize(agencyName);
      if (!nameMatches || status !== "active") return false;

      const effectiveOk = !agreement.effective_date || new Date(agreement.effective_date) <= now;
      const expiryOk = !agreement.expiry_date || new Date(agreement.expiry_date) >= now;
      return effectiveOk && expiryOk;
    })
    .sort((a, b) => new Date(b.updated_at || b.created_at || 0) - new Date(a.updated_at || a.created_at || 0))[0] || null;
}

function getAgencyAgreementPolicy(agencyName) {
  const activeAgreement = getActiveAgencyAgreement(agencyName);
  return {
    agreement: activeAgreement,
    agreement_no: activeAgreement?.agreement_no || "Default Policy",
    has_active_agreement: Boolean(activeAgreement),
    sla_days: numberOrDefault(activeAgreement?.sla_days, 60),
    response_sla_hours: numberOrDefault(activeAgreement?.response_sla_hours, 24),
    update_frequency_days: numberOrDefault(activeAgreement?.update_frequency_days, 7),
    delay_penalty_type: activeAgreement?.delay_penalty_type || "Fixed Amount Per Delayed Day",
    delay_penalty_amount: numberOrDefault(activeAgreement?.delay_penalty_amount, 0),
    delay_penalty_after_days: numberOrDefault(activeAgreement?.delay_penalty_after_days, 7),
    financial_guarantee_required: activeAgreement?.financial_guarantee_required || "No",
    financial_guarantee_amount: numberOrDefault(activeAgreement?.financial_guarantee_amount, 0),
    replacement_guarantee_days: numberOrDefault(activeAgreement?.replacement_guarantee_days, 90),
  };
}

function getCandidateCycleDays(candidate) {
  if (!candidate) return 0;
  const request = requests.find((item) => String(item.request_no || "") === String(candidate.request_no || ""));
  const start = request?.created_at || candidate.created_at;
  const end = candidate.joining_date || candidate.arrival_date || candidate.updated_at || new Date().toISOString();
  if (!start || !end) return 0;
  const days = Math.floor((new Date(end) - new Date(start)) / (1000 * 60 * 60 * 24));
  return Number.isFinite(days) ? Math.max(days, 0) : 0;
}

function getCandidateSlaDelay(candidate, agencyName = candidate?.agency) {
  const policy = getAgencyAgreementPolicy(agencyName);
  const cycleDays = getCandidateCycleDays(candidate);
  const delayDays = Math.max(cycleDays - Number(policy.sla_days || 60), 0);
  const penaltyDays = Math.max(delayDays - Number(policy.delay_penalty_after_days || 0), 0);
  const fixedPenalty = String(policy.delay_penalty_type || "").toLowerCase().includes("fixed")
    ? penaltyDays * Number(policy.delay_penalty_amount || 0)
    : 0;

  return {
    cycleDays,
    delayDays,
    penaltyDays,
    penaltyExposure: fixedPenalty,
    policy,
    isDelayed: delayDays > 0,
  };
}



const SLA_DELIVERED_WORKER_STATUSES = [
  "Arrived KSA",
  "Arrived",
  "Joined",
];

const SLA_FAILED_WORKER_STATUSES = [
  "Rejected",
  "Interview Failed",
  "Medical Failed",
  "Cancelled",
  "KSA Medical Failed",
  "Refused to Work",
  "Absconded",
];

function isDeliveredWorkerForSla(candidate) {
  if (!candidate) return false;
  return (
    SLA_DELIVERED_WORKER_STATUSES.includes(candidate.status) ||
    Boolean(candidate.arrival_date) ||
    Boolean(candidate.joining_date)
  );
}

function isFailedWorkerForSla(candidate) {
  if (!candidate) return false;
  return SLA_FAILED_WORKER_STATUSES.includes(candidate.status);
}

function candidateMatchesPenaltyLine(candidate, line) {
  if (!candidate || !line) return false;

  if (candidate.request_line_id && line.id) {
    return String(candidate.request_line_id) === String(line.id);
  }

  const professionOk = isUnifiedProfessionMatch(candidate.profession, line.profession);
  const nationalityOk = normalize(candidate.nationality) === normalize(line.nationality);
  const genderOk = !candidate.gender || !line.gender || normalize(candidate.gender) === normalize(line.gender);

  return professionOk && nationalityOk && genderOk;
}

function getAgencyNotificationPayload(item = {}) {
  return item?.data || {};
}

function getAgencyNotificationRequestNo(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return item?.request_no || data.request_no || data.requestNo || item?.related_id || "";
}

function getAgencyNotificationAgencyName(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return item?.agency_name || data.agency_name || data.agency || "";
}

function getAgencyNotificationResponseStatus(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return item?.response_status || data.response_status || data.agency_decision || "Pending";
}

function getAgencyNotificationSlaStartedAt(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return item?.sla_started_at || data.sla_started_at || "";
}

function getAgencyNotificationSlaDays(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return Number(item?.sla_days || data.sla_days || 0);
}

function getAgencyNotificationSlaDueAt(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return item?.sla_due_at || data.sla_due_at || "";
}

function getAgencyNotificationLines(item = {}) {
  const data = getAgencyNotificationPayload(item);
  return Array.isArray(data.lines) ? data.lines : [];
}

function getAcceptedAgencyRequestPenaltyAlerts() {
  const penaltyNotificationTypes = new Set([
    "NEW_REQUEST_AGENCY_ALERT",
    "AGENCY_REQUEST_NOTIFICATION",
  ]);

  return (notifications || []).filter((item) => {
    const data = getAgencyNotificationPayload(item);
    const notificationType = String(item?.type || data.type || "").trim();
    const accepted = ["accepted", "accept"].includes(normalize(getAgencyNotificationResponseStatus(item)));
    const hasSlaStart = Boolean(getAgencyNotificationSlaStartedAt(item));
    const hasLines = getAgencyNotificationLines(item).length > 0;
    return penaltyNotificationTypes.has(notificationType) && accepted && hasSlaStart && hasLines;
  });
}

function getPenaltyLineSummary(lines = []) {
  const labels = (lines || [])
    .map((line) => `${line.profession || "-"} / ${line.nationality || "-"} / ${line.gender || "-"}`)
    .filter(Boolean);
  const unique = Array.from(new Set(labels));
  if (unique.length === 0) return "Accepted request lines";
  if (unique.length <= 2) return unique.join(" | ");
  return `Multiple accepted lines (${unique.length})`;
}

function getAgencyAlertCandidateRows(alert) {
  const alertLines = getAgencyNotificationLines(alert);
  const requestNo = String(getAgencyNotificationRequestNo(alert) || "").trim();
  const agencyName = getAgencyNotificationAgencyName(alert) || "";

  return (candidates || []).filter((candidate) => {
    if (requestNo && String(candidate.request_no || "") !== requestNo) return false;
    if (agencyName && normalize(candidate.agency) !== normalize(agencyName)) return false;
    if (isFailedWorkerForSla(candidate)) return false;
    return alertLines.some((line) => candidateMatchesPenaltyLine(candidate, line));
  });
}

function getPenaltyRowUniqueKey(item = {}) {
  if (item.candidate_id) {
    return `candidate:${String(item.candidate_id)}:${String(item.agreement_no || "")}`;
  }

  return [
    "agency-request",
    normalize(item.agency_name),
    String(item.request_no || ""),
    String(item.agreement_no || ""),
    normalize(item.profession),
  ].join(":");
}

function calculateAcceptedAgencyRequestPenaltyRows() {
  const today = new Date();

  return getAcceptedAgencyRequestPenaltyAlerts()
    .map((alert) => {
      const data = getAgencyNotificationPayload(alert);
      const agencyName = getAgencyNotificationAgencyName(alert) || "Unassigned Agency";
      const requestNo = getAgencyNotificationRequestNo(alert);
      const policy = getAgencyAgreementPolicy(agencyName);
      const agreement = policy.agreement || null;
      const agency = agencies.find((item) => normalize(item.name) === normalize(agencyName));
      const request = requests.find((item) => String(item.request_no || "") === String(requestNo || ""));
      const lines = getAgencyNotificationLines(alert);
      const assignedQty = lines.reduce((sum, line) => {
        const lineQty = Number(line.quantity ?? line.qty ?? line.allocated_qty ?? line.assigned_qty ?? 0);
        return sum + (Number.isFinite(lineQty) ? lineQty : 0);
      }, 0);

      const startedAtRaw = getAgencyNotificationSlaStartedAt(alert);
      const startedAt = new Date(startedAtRaw);
      if (!assignedQty || Number.isNaN(startedAt.getTime())) return null;

      const notificationSlaDays = getAgencyNotificationSlaDays(alert);
      const slaDays = numberOrDefault(notificationSlaDays, numberOrDefault(policy.sla_days, 60));
      const dueAtRaw = getAgencyNotificationSlaDueAt(alert);
      const dueAt = dueAtRaw ? new Date(dueAtRaw) : new Date(addDaysToIso(startedAtRaw, slaDays));
      const actualDays = Math.max(0, Math.floor((today - startedAt) / (1000 * 60 * 60 * 24)));
      const delayDays = Math.max(Math.floor((today - dueAt) / (1000 * 60 * 60 * 24)), 0);
      const graceDays = numberOrDefault(policy.delay_penalty_after_days, 0);
      const penaltyDays = Math.max(delayDays - graceDays, 0);
      const deliveredQty = getAgencyAlertCandidateRows(alert).filter(isDeliveredWorkerForSla).length;
      const delayedWorkers = Math.max(assignedQty - deliveredQty, 0);
      const fixedPenalty = String(policy.delay_penalty_type || "").toLowerCase().includes("fixed");
      const penaltyRate = numberOrDefault(policy.delay_penalty_amount, 0);
      const calculatedAmount = fixedPenalty ? delayedWorkers * penaltyDays * penaltyRate : 0;

      if (delayDays <= 0 || penaltyDays <= 0 || delayedWorkers <= 0 || calculatedAmount <= 0) return null;

      return {
        company_id: currentCompanyId,
        penalty_no: "",
        agreement_id: agreement?.id || null,
        agreement_no: policy.agreement_no || "Default Policy",
        agency_id: agency?.id || alert.agency_id || null,
        agency_name: agencyName,
        candidate_id: null,
        candidate_name: `${delayedWorkers} delayed worker(s) from ${assignedQty} assigned`,
        request_no: requestNo || "-",
        profession: getPenaltyLineSummary(lines),
        project: data.project_name || request?.project_name || request?.project || "-",
        status: "Pending Review",
        sla_days: slaDays,
        actual_days: actualDays,
        delay_days: delayDays,
        grace_days: graceDays,
        penalty_days: penaltyDays,
        penalty_type: policy.delay_penalty_type || "Fixed Amount Per Delayed Day",
        penalty_rate: penaltyRate,
        calculated_amount: calculatedAmount,
        approved_amount: null,
        decision_notes: `Auto calculated on delayed workers only. Assigned: ${assignedQty}, Delivered/Arrived/Joined: ${deliveredQty}, Delayed: ${delayedWorkers}. Source notification: ${alert.id || "-"}.`,
        agency_justification: "",
        source: "live",
        source_notification_id: alert.id || "",
        assigned_qty: assignedQty,
        delivered_qty: deliveredQty,
        delayed_workers: delayedWorkers,
      };
    })
    .filter(Boolean)
    .sort((a, b) => Number(b.calculated_amount || 0) - Number(a.calculated_amount || 0));
}

function generatePenaltyNo(indexOffset = 0) {
  const year = new Date().getFullYear();
  const prefix = `PEN-${year}-`;
  const maxNumber = agencyPenalties.reduce((max, item) => {
    const penaltyNo = String(item.penalty_no || "");
    if (!penaltyNo.startsWith(prefix)) return max;
    const numberPart = Number(penaltyNo.replace(prefix, ""));
    return Number.isFinite(numberPart) ? Math.max(max, numberPart) : max;
  }, 0);
  return `${prefix}${String(maxNumber + 1 + indexOffset).padStart(4, "0")}`;
}

function calculatePenaltyRegisterRows() {
  // Financial penalty is calculated on delayed workers only:
  // accepted quantity assigned to the agency - delivered/arrived/joined workers after SLA + grace period.
  return calculateAcceptedAgencyRequestPenaltyRows();
}

function getPenaltyRegisterDisplayRows() {
  const savedRows = (agencyPenalties || []).map((item) => ({ ...item, source: "saved" }));
  const savedKeys = new Set(savedRows.map(getPenaltyRowUniqueKey));
  const liveRows = calculatePenaltyRegisterRows()
    .filter((item) => !savedKeys.has(getPenaltyRowUniqueKey(item)))
    .map((item) => ({ ...item, status: "Calculated - Not Saved", source: "live" }));
  return [...savedRows, ...liveRows].sort((a, b) => {
    const statusWeight = { "Agency Objection Submitted": 0, "Justification Submitted": 0, "Pending Review": 1, "Calculated - Not Saved": 2, "Sent to Agency": 3, Approved: 4, Reduced: 5, Waived: 6 };
    return (statusWeight[a.status] ?? 9) - (statusWeight[b.status] ?? 9) || Number(b.calculated_amount || 0) - Number(a.calculated_amount || 0);
  });
}

async function generatePenaltyRegister() {
  if (!canApprovePenalties) return alert("You do not have permission to generate penalty records.");
  const liveRows = calculatePenaltyRegisterRows();
  if (!liveRows.length) return alert("No calculated penalties found based on the active agreements.");

  let inserted = 0;
  let updated = 0;
  for (const [index, row] of liveRows.entries()) {
    const rowKey = getPenaltyRowUniqueKey(row);
    const existing = agencyPenalties.find((item) => getPenaltyRowUniqueKey(item) === rowKey);

    const payload = {
      ...row,
      penalty_no: existing?.penalty_no || generatePenaltyNo(index),
      candidate_id: row.candidate_id ? String(row.candidate_id) : null,
      status: existing?.status || "Pending Review",
      approved_amount: existing?.approved_amount ?? null,
      decision_notes: existing?.decision_notes || row.decision_notes || "",
      updated_at: new Date().toISOString(),
    };
    delete payload.source;
    delete payload.source_notification_id;
    delete payload.assigned_qty;
    delete payload.delivered_qty;
    delete payload.delayed_workers;
    delete payload.penalty_key;

    if (existing?.id) {
      if (["Approved", "Reduced", "Waived"].includes(existing.status)) continue;
      const { error } = await supabase
        .from("agency_penalties")
        .update(payload)
        .eq("id", existing.id)
        .eq("company_id", currentCompanyId);
      if (error) return alert(error.message);
      updated += 1;
    } else {
      const { error } = await supabase.from("agency_penalties").insert([withCompany({ ...payload, created_at: new Date().toISOString() })]);
      if (error) return alert(error.message);
      inserted += 1;
    }
  }

  await loadAgencyPenalties();
  alert(`Penalty register updated. Inserted: ${inserted}, Updated: ${updated}`);
}

async function createPenaltyRecord(item) {
  if (!canApprovePenalties) return alert("You do not have permission to create penalty records.");
  if (!item || item.source !== "live") return alert("This penalty record is already saved or not available for creation.");

  const existing = agencyPenalties.find((row) => getPenaltyRowUniqueKey(row) === getPenaltyRowUniqueKey(item));
  if (existing?.id) {
    return alert(`Penalty record already exists: ${existing.penalty_no || existing.id}`);
  }

  const payload = {
    ...item,
    penalty_no: generatePenaltyNo(),
    candidate_id: item.candidate_id ? String(item.candidate_id) : null,
    status: "Pending Review",
    approved_amount: null,
    decision_notes: item.decision_notes || "Auto calculated from accepted agency request notification. Pending management review.",
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };

  delete payload.source;
  delete payload.source_notification_id;
  delete payload.assigned_qty;
  delete payload.delivered_qty;
  delete payload.delayed_workers;
  delete payload.penalty_key;

  const { error } = await supabase
    .from("agency_penalties")
    .insert([withCompany(payload)]);

  if (error) return alert(error.message);

  await loadAgencyPenalties();
  alert("Penalty record created as Pending Review.");
}

async function sendPenaltyToAgency(item, amountOverride = null, noteOverride = "") {
  if (!canApprovePenalties) return alert("You do not have permission to send penalties to agency.");
  if (!item?.id) return alert("Please generate the penalty register first.");
  const amount = amountOverride === null ? Number(item.approved_amount ?? item.calculated_amount ?? 0) : Number(amountOverride || 0);
  const now = new Date().toISOString();
  const { error } = await supabase
    .from("agency_penalties")
    .update({
      status: "Sent to Agency",
      approved_amount: amount,
      decision_notes: noteOverride || item.decision_notes || "Penalty issued to agency for justification window.",
      decision_by: currentUser?.name || currentUser?.email || "Company User",
      decision_role: currentRole,
      decision_at: now,
      sent_to_agency_at: now,
      updated_at: now,
    })
    .eq("id", item.id)
    .eq("company_id", currentCompanyId);
  if (error) return alert(error.message);

  try {
    await triggerExternalNotification("AGENCY_PENALTY_SENT", {
      company_id: currentCompanyId,
      agency_id: item.agency_id || null,
      agency_name: item.agency_name || "",
      title: `Penalty sent to agency - ${item.penalty_no || "Penalty"}`,
      message: `Penalty ${item.penalty_no || ""} for request ${item.request_no || "-"} has been sent to the agency for justification. Amount: ${amount.toLocaleString()} SAR`,
      priority: "High",
      related_table: "agency_penalties",
      related_id: String(item.id || ""),
      penalty_no: item.penalty_no || "",
      request_no: item.request_no || "",
      approved_amount: amount,
    });
  } catch (notificationError) {
    console.warn("Penalty portal notification failed", notificationError?.message || notificationError);
  }

  try {
    await sendPenaltyNoticeEmail({
      ...item,
      status: "Sent to Agency",
      approved_amount: amount,
      decision_notes: noteOverride || item.decision_notes || "Penalty issued to agency for justification window.",
    });
  } catch (emailError) {
    console.warn("Penalty notice email failed", emailError?.message || emailError);
  }
  await loadAgencyPenalties();
}

async function reduceAndSendPenalty(item) {
  const currentAmount = Number(item.approved_amount ?? item.calculated_amount ?? 0);
  const newAmountText = window.prompt("Enter reduced penalty amount SAR", String(currentAmount));
  if (newAmountText === null) return;
  const newAmount = Number(newAmountText);
  if (!Number.isFinite(newAmount) || newAmount < 0) return alert("Invalid amount.");
  const note = window.prompt("Reason for reduction", item.decision_notes || "") || "Reduced by management before sending to agency.";
  await sendPenaltyToAgency(item, newAmount, note);
}

