async function runAIAgentAutoManagerApprovals({ limit = getAIAgentMaxAutoActions() } = {}) {
  if (!currentCompanyId || isCurrentAgencyUser) return;
  if (!isAIAgentManagerAutoEnabled()) return;
  if (!canManageAgencyAgreements && !canManageCandidates && !canManageUsers && !canManagePlatform) return;
  if (!requests.length || !agencies.length) return;

  const recommendations = getAIAgentRequestAssignmentRecommendations()
    .filter((item) => item?.bestAgency)
    .slice(0, limit);

  if (!recommendations.length) return;

  setAiAgentLoading(true);
  try {
    let created = 0;
    let skipped = 0;

    for (const item of recommendations) {
      const result = await prepareAIAgentAssignmentApproval(item, {
        silent: true,
        preventDuplicate: true,
        auto: true,
      });

      if (result?.skipped) skipped += 1;
      else if (result?.ok) created += 1;
    }

    if (created > 0) {
      const summary = `AI Agent Auto Mode sent ${created} manager approval notification(s). ${skipped ? `${skipped} duplicate item(s) skipped.` : ""}`;
      setAiAgentLog(summary);
      setAiAgentLastRun(new Date().toLocaleString());
      await loadNotifications();
      await loadEmailLogs();
    }
  } catch (error) {
    console.warn("AI Agent Auto Mode failed", error?.message || error);
    setAiAgentLog(`AI Agent Auto Mode failed: ${error.message}`);
  } finally {
    setAiAgentLoading(false);
  }
}

async function hasAIAgentFollowUpToday(task, type = "AI_AGENT_AUTO_AGENCY_FOLLOWUP") {
  if (!currentCompanyId || !task) return false;

  const startOfDay = new Date();
  startOfDay.setHours(0, 0, 0, 0);

  let query = supabase
    .from("notification_events")
    .select("id")
    .eq("company_id", currentCompanyId)
    .eq("type", type)
    .eq("related_table", task.related_table || "")
    .eq("related_id", task.related_id || "")
    .gte("created_at", startOfDay.toISOString())
    .limit(1);

  if (task.agency_id) query = query.eq("agency_id", task.agency_id);

  const { data, error } = await query;
  if (error) {
    console.warn("AI Agent follow-up duplicate check failed", error.message);
    return false;
  }

  return (data || []).length > 0;
}

async function sendAIAgentAgencyFollowUpTask(task, options = {}) {
  const { auto = false, sendEmail = false } = options;
  const email = buildAIAgentAgencyEmail(task);
  const type = auto ? "AI_AGENT_AUTO_AGENCY_FOLLOWUP" : "AI_AGENT_AGENCY_FOLLOWUP";
  const actionKey = getAIAgentFollowUpDedupeKey(task);

  const lock = await acquireAIAgentActionLock({
    actionType: type,
    actionKey,
    relatedTable: task.related_table || "",
    relatedId: task.related_id || "",
    agencyId: task.agency_id || null,
    title: task.title || "Agency follow-up",
    details: { agency: task.agency, request_no: task.request_no, priority: task.priority, sendEmail, auto },
  });

  if (!lock.ok) return { ok: true, skipped: true, reason: lock.reason || "Duplicate lock" };

  await triggerExternalNotification(type, {
    company_id: currentCompanyId,
    agency_id: task.agency_id || null,
    agency_name: task.agency,
    agency_email: task.agency_email || "",
    title: task.title,
    message: email.body,
    subject: email.subject,
    priority: task.priority,
    related_table: task.related_table,
    related_id: task.related_id,
    source: auto ? "AI Agent Auto Follow-up" : "AI Commander / AI Agent",
    delivery_channel: sendEmail ? "Notification + Email" : "Notification Only",
    auto_generated: auto,
    dedupe_key: getAIAgentFollowUpDedupeKey(task),
    task,
  });

  if (sendEmail && task.agency_email) {
    await dispatchVisaFlowEmail({
      type,
      to: task.agency_email,
      subject: email.subject,
      text: email.body,
      html: buildEmailCardHtml(email.subject, email.body.split("\n"), "This follow-up was generated by VisaFlow AI Recruitment Agent."),
      payload: {
        agency: task.agency,
        request_no: task.request_no,
        reference: task.reference,
        priority: task.priority,
        auto_generated: auto,
        dedupe_key: actionKey,
      },
    });
  }

  await writeAIAgentAuditLog({
    actionType: type,
    actionKey,
    status: "completed",
    severity: task.priority === "High" ? "warning" : "info",
    title: task.title,
    targetTable: task.related_table,
    targetId: task.related_id,
    agencyId: task.agency_id || null,
    agencyName: task.agency,
    requestNo: task.request_no,
    details: { task, sendEmail, auto },
  });

  return { ok: true, skipped: false, emailSkipped: Boolean(sendEmail && !task.agency_email) };
}

async function processAIAgentAgencyFollowUps(options = {}) {
  const { auto = false, limit = 50, silent = false, sendEmail = false } = options;

  if (!canManageAgencyAgreements && !canManageCandidates && !canManageVisas && !canManageUsers && !canManagePlatform) {
    if (!silent) alert("You do not have permission to run AI Agent follow-up.");
    return { ok: false, created: 0, skipped: 0, reason: "Permission denied" };
  }

  if (auto && !isAIAgentAgencyFollowUpAutoEnabled()) {
    return { ok: true, created: 0, skipped: 0, reason: "Auto follow-up is disabled" };
  }

  const tasks = getAIAgentAgencyTasks();
  if (!tasks.length) {
    if (!silent) {
      setAiAgentLog("No agency follow-up tasks found. All agencies are within current follow-up rules.");
      setAiAgentLastRun(new Date().toLocaleString());
      alert("No agency follow-up tasks found.");
    }
    return { ok: true, created: 0, skipped: 0, reason: "No tasks" };
  }

  setAiAgentLoading(true);
  if (!silent) setAiAgentLog("");

  try {
    const selectedTasks = tasks.slice(0, limit);
    let created = 0;
    let skipped = 0;
    let emailSkipped = 0;

    for (const task of selectedTasks) {
      if (auto && await hasAIAgentFollowUpToday(task, "AI_AGENT_AUTO_AGENCY_FOLLOWUP")) {
        skipped += 1;
        continue;
      }

      const result = await sendAIAgentAgencyFollowUpTask(task, { auto, sendEmail });
      if (result?.skipped) {
        skipped += 1;
        continue;
      }
      created += 1;
      if (result?.emailSkipped) emailSkipped += 1;
    }

    const summary = `${auto ? "AI Agent Auto Follow-up" : "AI Agent Manual Follow-up"} completed for ${created} item(s). ${skipped ? `${skipped} duplicate item(s) skipped for today.` : ""}${sendEmail ? ` ${emailSkipped ? `${emailSkipped} item(s) had no agency email.` : "Emails enabled."}` : " Notifications only."}\n\n` +
      selectedTasks.slice(0, 10).map((task, index) => `${index + 1}. [${task.priority}] ${task.agency} - ${task.title}`).join("\n") +
      (selectedTasks.length > 10 ? `\n...and ${selectedTasks.length - 10} more.` : "");

    setAiAgentLog(summary);
    setAiAgentLastRun(new Date().toLocaleString());
    await loadNotifications();
    if (sendEmail) await loadEmailLogs();

    if (!silent) alert(`AI Agent follow-up created: ${created} item(s).`);
    return { ok: true, created, skipped };
  } catch (error) {
    setAiAgentLog(`AI Agent failed: ${error.message}`);
    if (!silent) alert(error.message);
    return { ok: false, created: 0, skipped: 0, reason: error.message };
  } finally {
    setAiAgentLoading(false);
  }
}

async function runAIAgentAutoAgencyFollowUp({ limit = getAIAgentMaxAutoActions() } = {}) {
  return processAIAgentAgencyFollowUps({
    auto: true,
    limit,
    silent: true,
    sendEmail: shouldAIAgentSendAgencyEmails(),
  });
}

async function runAIAgentAgencyFollowUp() {
  return processAIAgentAgencyFollowUps({
    auto: false,
    limit: 50,
    silent: false,
    sendEmail: shouldAIAgentSendAgencyEmails(),
  });
}

function getCandidateRequest(candidate) {
  return requests.find((request) => String(request.request_no || "") === String(candidate?.request_no || ""));
}

function getCandidateOfferData(candidate) {
  const req = getCandidateRequest(candidate) || {};
  const salary = candidate?.salary || req.salary || req.budget || "To be confirmed";
  const project = candidate?.project || req.project_name || req.project || "Company Project";
  const joiningDate = candidate?.joining_date || "To be confirmed";
  const isSaudiFlow = isSaudiCandidate(candidate, requests);

  return {
    candidateName: candidate?.candidate_name || "Candidate",
    candidateEmail: candidate?.email || "",
    profession: candidate?.profession || req.profession || "Position",
    nationality: candidate?.nationality || req.nationality || "-",
    project,
    salary,
    joiningDate,
    requestNo: candidate?.request_no || req.request_no || "-",
    recruitmentType: isSaudiFlow ? "Saudi Hiring" : "Foreign Recruitment",
    companyName: "VisaFlow KSA Client",
  };
}

function buildOfferSubject(candidate) {
  const data = getCandidateOfferData(candidate);
  return `Job Offer - ${data.profession} - ${data.candidateName}`;
}

function buildOfferBody(candidate) {
  const data = getCandidateOfferData(candidate);
  return `Dear ${data.candidateName},

We are pleased to inform you that you have successfully passed the interview for the position of ${data.profession}.

We are delighted to extend this job offer to you based on the following initial details:

Position: ${data.profession}
Project / Department: ${data.project}
Recruitment Type: ${data.recruitmentType}
Monthly Salary / Package: ${data.salary} SAR
Expected Joining Date: ${data.joiningDate}
Reference Request No: ${data.requestNo}

Please reply to this email confirming your acceptance of the offer. Once your acceptance is received, the recruitment team will proceed with the next steps.

Best regards,
Recruitment Department
${data.companyName}`;
}

async function generateOfferWithAI(candidate) {
  const data = getCandidateOfferData(candidate);

  try {
    const aiDraft = await callVisaFlowAIEdge({
      action: "offer",
      offerData: data,
      language: "English",
    });

    return aiDraft || buildOfferBody(candidate);
  } catch (error) {
    console.warn("AI offer generation failed", error?.message || error);
    return buildOfferBody(candidate);
  }
}

async function openOfferEmail(candidate) {
  if (!candidate) return alert("Candidate not found.");

  setOfferCandidate(candidate);
  setOfferSubject(buildOfferSubject(candidate));
  setOfferBody(buildOfferBody(candidate));
  setOfferMessage("");
  setOfferModalOpen(true);

  setOfferLoading(true);
  try {
    const aiDraft = await generateOfferWithAI(candidate);
    setOfferBody(aiDraft);
  } finally {
    setOfferLoading(false);
  }
}

async function sendOfferEmail() {
  if (!offerCandidate) return alert("Candidate is required.");
  if (!offerCandidate.email) return alert("Candidate email is missing. Please add candidate email first.");
  if (!offerSubject || !offerBody) return alert("Offer subject and body are required.");

  setOfferLoading(true);
  setOfferMessage("");

  const payload = {
    type: "JOB_OFFER_EMAIL",
    to: offerCandidate.email,
    subject: offerSubject,
    body: offerBody,
    candidate_id: offerCandidate.id,
    candidate_name: offerCandidate.candidate_name,
    request_no: offerCandidate.request_no,
    profession: offerCandidate.profession,
    created_by: currentUser?.email || currentUser?.name || "VisaFlow User",
    created_at: new Date().toISOString(),
  };

  try {
    const emailResult = await dispatchVisaFlowEmail({
      type: "JOB_OFFER_EMAIL",
      to: offerCandidate.email,
      subject: offerSubject,
      text: offerBody,
      html: buildEmailCardHtml(offerSubject, offerBody.split("\n").filter(Boolean)),
      replyTo: getCompanyEmailRecipient("support"),
      payload,
    });

    const deliveryStatus = "SENT";
    const providerMessage = `Offer email sent successfully${emailResult?.messageId ? ` (${emailResult.messageId})` : ""}.`;

    await triggerExternalNotification("JOB_OFFER_EMAIL", {
      ...payload,
      delivery_status: deliveryStatus,
      provider_message: providerMessage,
    });

    await supabase
      .from("candidates")
      .update(withUpdateActor({
        offer_status: "Sent",
        contract_status: "Sent",
        status: offerCandidate.status === "Interview Passed" ? "Selected" : offerCandidate.status,
        updated_at: new Date().toISOString(),
      }))
      .eq("id", offerCandidate.id);

    await loadCandidates();
    setOfferMessage(providerMessage);
  } catch (error) {
    setOfferMessage(`Failed to send offer email: ${error.message}`);
  } finally {
    setOfferLoading(false);
  }
}


function generateMarketplaceNo(prefix, rows, field, digits = 4) {
  const year = new Date().getFullYear();
  const maxNumber = (rows || []).reduce((max, item) => {
    const value = String(item?.[field] || "");
    const parts = value.split("-");
    if (parts[0] !== prefix || parts[1] !== String(year)) return max;
    const n = parseInt(parts[2] || "0", 10);
    return Number.isFinite(n) ? Math.max(max, n) : max;
  }, 0);
  return `${prefix}-${year}-${String(maxNumber + 1).padStart(digits, "0")}`;
}

function resetMarketplaceRequestForm() {
  setMarketplaceRequestForm(emptyMarketplaceRequest);
  setMarketplaceRequestEditingId(null);
  setMarketplaceSelectedEmployeeIds([]);
}

function editMarketplaceRequest(item) {
  const sourceEmployeeIds = parseMarketplaceEmployeeIds(item.source_employee_ids);
  setMarketplaceSelectedEmployeeIds(sourceEmployeeIds);
  setMarketplaceRequestEditingId(item.id);
  setMarketplaceRequestForm({
    ...emptyMarketplaceRequest,
    request_no: item.request_no || "",
    client_name: item.client_name || "",
    deal_type: item.deal_type || item.service_type || "Service Rental",
    profession: item.profession || "",
    nationality: item.nationality || "",
    gender: item.gender || "",
    quantity: item.quantity || "",
    duration_months: item.duration_months || 12,
    base_salary: item.base_salary || "",
    annual_medical_insurance: item.annual_medical_insurance || (item.monthly_medical_insurance ? roundMoney(Number(item.monthly_medical_insurance || 0) * 12) : ""),
    monthly_medical_insurance: item.monthly_medical_insurance || "",
    pricing_method: item.pricing_method || "Margin Percent",
    margin_percent: item.margin_percent ?? "15",
    manual_monthly_rate: item.manual_monthly_rate || item.monthly_rate || "",
    monthly_rate: item.monthly_rate || "",
    iqama_expiry_date: item.iqama_expiry_date || "",
    insurance_policy_end_date: item.insurance_policy_end_date || "",
    transfer_remaining_months: item.transfer_remaining_months || "",
    transfer_medical_insurance_remaining: item.transfer_medical_insurance_remaining || item.medical_insurance_remaining || "",
    transfer_service_fee: item.transfer_service_fee || "",
    admin_fee_method: item.admin_fee_method || "Percent",
    admin_fee_percent: item.admin_fee_percent ?? "10",
    admin_fee_amount: item.admin_fee_amount || "",
    transfer_status: item.transfer_status || "Transfer Pending",
    source_type: item.source_type || (sourceEmployeeIds.length ? "Employees Selection" : "Manual"),
    source_employee_ids: sourceEmployeeIds,
    selected_workers: item.selected_workers || [],
    status: item.status || "Open",
    notes: item.notes || "",
  });
  setActivePage("Workforce Marketplace");
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function parseMarketplaceEmployeeIds(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value.map((item) => String(item)).filter(Boolean);
  if (typeof value === "string") {
    try {
      const parsed = JSON.parse(value);
      if (Array.isArray(parsed)) return parsed.map((item) => String(item)).filter(Boolean);
    } catch {
      return value.split(/[,\n]/).map((item) => item.trim()).filter(Boolean);
    }
  }
  return [];
}

function getSelectedMarketplaceEmployees(ids = marketplaceSelectedEmployeeIds) {
  const idSet = new Set((ids || []).map((id) => String(id)));
  return employees.filter((employee) => idSet.has(String(employee.id)));
}

function getCommonEmployeeValue(rows = [], field) {
  const values = Array.from(new Set(rows.map((row) => String(row?.[field] || "").trim()).filter(Boolean)));
  if (values.length === 0) return "";
  if (values.length === 1) return values[0];
  return "Multiple";
}

function getCommonEmployeeDate(rows = [], field) {
  const value = getCommonEmployeeValue(rows, field);
  return value === "Multiple" ? "" : value;
}

function getCommonEmployeeNumber(rows = [], field) {
  const value = getCommonEmployeeValue(rows, field);
  return value === "Multiple" ? "" : value;
}

function getEmployeeMarketplaceStatus(employee = {}) {
  return employee.marketplace_status || "Available";
}

function isEmployeeReservedForMarketplace(employee = {}) {
  return ["Reserved", "Rented", "Transfer In Progress", "Transferred"].includes(getEmployeeMarketplaceStatus(employee));
}

function buildSelectedWorkerSnapshot(rows = []) {
  return rows.map((employee) => ({
    employee_id: String(employee.id || ""),
    employee_no: employee.employee_no || "",
    employee_name: employee.employee_name || "",
    iqama_no: employee.iqama_no || "",
    iqama_expiry_date: employee.iqama_expiry_date || null,
    insurance_policy_end_date: employee.insurance_policy_end_date || null,
    annual_medical_insurance: Number(employee.annual_medical_insurance || 0) || roundMoney(Number(employee.monthly_medical_insurance || 0) * 12),
    monthly_medical_insurance: Number(employee.monthly_medical_insurance || 0),
    profession: employee.profession || "",
    nationality: employee.nationality || "",
    gender: employee.gender || "",
    project_name: employee.project_name || "",
    marketplace_status: getEmployeeMarketplaceStatus(employee),
  }));
}

function buildSelectedWorkersNotes(rows = []) {
  if (!rows.length) return "";
  return [
    "Selected from Employees for Workforce Marketplace:",
    ...rows.map((employee, index) => `${index + 1}. ${employee.employee_name || employee.employee_no || employee.id} | ${employee.profession || "-"} | Iqama: ${employee.iqama_no || "-"} | Iqama Expiry: ${employee.iqama_expiry_date || "-"}`),
  ].join("\n");
}

function toggleEmployeeSelection(employeeId, disabled = false) {
  if (disabled) return;
  const id = String(employeeId || "");
  if (!id) return;
  setSelectedEmployeeIds((prev) => prev.includes(id) ? prev.filter((item) => item !== id) : [...prev, id]);
}

function toggleAllVisibleEmployeesSelection(rows = filteredEmployeeRows) {
  const availableIds = (rows || [])
    .filter((employee) => !isEmployeeReservedForMarketplace(employee))
    .map((employee) => String(employee.id));

  if (!availableIds.length) return;

  const allSelected = availableIds.every((id) => selectedEmployeeIds.includes(id));
  setSelectedEmployeeIds((prev) => allSelected
    ? prev.filter((id) => !availableIds.includes(String(id)))
    : Array.from(new Set([...prev, ...availableIds]))
  );
}

function sendSelectedEmployeesToMarketplace() {
  if (!canManageMarketplace) return alert("You do not have permission to manage Workforce Marketplace.");

  const selectedRows = employees.filter((employee) => selectedEmployeeIds.includes(String(employee.id)));
  if (!selectedRows.length) return alert("Please select at least one employee first.");

  const blockedRows = selectedRows.filter(isEmployeeReservedForMarketplace);
  const rows = selectedRows.filter((employee) => !isEmployeeReservedForMarketplace(employee));

  if (!rows.length) {
    return alert("All selected employees are already reserved or linked to a marketplace deal.");
  }

  if (blockedRows.length > 0) {
    alert(`${blockedRows.length} selected employee(s) were skipped because they are already reserved or linked to a marketplace deal.`);
  }

  const ids = rows.map((employee) => String(employee.id));
  const notes = buildSelectedWorkersNotes(rows);

  setMarketplaceSelectedEmployeeIds(ids);
  setMarketplaceRequestEditingId(null);
  setMarketplaceRequestForm({
    ...emptyMarketplaceRequest,
    source_type: "Employees Selection",
    source_employee_ids: ids,
    selected_workers: buildSelectedWorkerSnapshot(rows),
    deal_type: "Service Rental",
    profession: getCommonEmployeeValue(rows, "profession"),
    nationality: getCommonEmployeeValue(rows, "nationality"),
    gender: getCommonEmployeeValue(rows, "gender"),
    iqama_expiry_date: getCommonEmployeeDate(rows, "iqama_expiry_date"),
    insurance_policy_end_date: getCommonEmployeeDate(rows, "insurance_policy_end_date"),
    annual_medical_insurance: getCommonEmployeeNumber(rows, "annual_medical_insurance") || (getCommonEmployeeNumber(rows, "monthly_medical_insurance") ? roundMoney(Number(getCommonEmployeeNumber(rows, "monthly_medical_insurance") || 0) * 12) : ""),
    monthly_medical_insurance: getCommonEmployeeNumber(rows, "monthly_medical_insurance"),
    quantity: rows.length,
    duration_months: 12,
    notes,
  });

  setSelectedEmployeeIds([]);
  setActivePage("Workforce Marketplace");
  window.setTimeout(() => window.scrollTo({ top: 0, behavior: "smooth" }), 120);
}

function getMarketplaceDealWorkerRows(deal) {
  const dealId = String(deal?.id || "");
  return marketplaceDealWorkers.filter((worker) => String(worker.deal_id || "") === dealId);
}

async function attachWorkersToMarketplaceDeal(deal, rows = []) {
  if (!deal?.id || !rows.length) return;

  const workerPayload = rows.map((employee) => withCompany(withCreateActor({
    deal_id: String(deal.id || ""),
    deal_no: deal.deal_no || "",
    employee_id: String(employee.id || ""),
    employee_no: employee.employee_no || "",
    employee_name: employee.employee_name || "",
    iqama_no: employee.iqama_no || "",
    iqama_expiry_date: employee.iqama_expiry_date || null,
    insurance_policy_end_date: employee.insurance_policy_end_date || null,
    annual_medical_insurance: Number(employee.annual_medical_insurance || 0) || roundMoney(Number(employee.monthly_medical_insurance || 0) * 12),
    monthly_medical_insurance: Number(employee.monthly_medical_insurance || 0),
    profession: employee.profession || "",
    nationality: employee.nationality || "",
    gender: employee.gender || "",
    project_name: employee.project_name || "",
    worker_status: getWorkforceDealType(deal) === "Sponsorship Transfer" ? "Transfer In Progress" : "Reserved",
    notes: `Attached to marketplace deal ${deal.deal_no || ""}`,
  })));

  const { error: workerError } = await supabase.from("marketplace_deal_workers").insert(workerPayload);
  if (workerError) throw workerError;

  const marketplaceStatus = getWorkforceDealType(deal) === "Sponsorship Transfer" ? "Transfer In Progress" : "Reserved";
  for (const employee of rows) {
    const { error } = await supabase
      .from("employees")
      .update(withUpdateActor({
        marketplace_status: marketplaceStatus,
        marketplace_deal_id: String(deal.id),
        updated_at: new Date().toISOString(),
      }))
      .eq("id", employee.id)
      .eq("company_id", currentCompanyId);
    if (error) throw error;
  }
}

function roundMoney(value) {
  return Math.round(Number(value || 0) * 100) / 100;
}

function getDaysUntil(dateValue) {
  if (!dateValue) return 0;
  const end = new Date(dateValue);
  if (Number.isNaN(end.getTime())) return 0;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  end.setHours(0, 0, 0, 0);
  const days = Math.ceil((end - today) / (1000 * 60 * 60 * 24));
  return Math.max(days, 0);
}

function getMonthsUntil(dateValue) {
  return Math.max(Math.ceil(getDaysUntil(dateValue) / 30.4375), 0);
}

function getWorkforceDealType(item = {}) {
  const value = String(item.deal_type || item.service_type || "Service Rental");
  return value.toLowerCase().includes("transfer") || value.includes("تنازل") || value.includes("كفالة")
    ? "Sponsorship Transfer"
    : "Service Rental";
}

function getMarketplacePricingBreakdown(source = {}) {
  const dealType = getWorkforceDealType(source);
  const quantity = Math.max(Number(source.quantity || 0), 0);
  const durationMonths = Math.max(Number(source.duration_months || 1), 1);
  const baseSalary = Number(source.base_salary || source.salary || 0);
  const annualMedicalInsurance = Number(source.annual_medical_insurance || 0) || roundMoney(Number(source.monthly_medical_insurance || 0) * 12);
  const monthlyMedicalInsurance = annualMedicalInsurance > 0
    ? roundMoney(annualMedicalInsurance / 12)
    : Number(source.monthly_medical_insurance || 0);
  const monthlyIqamaWorkPermit = WORKFORCE_MONTHLY_IQAMA_WORK_PERMIT_COST;
  const gosiAmount = roundMoney(baseSalary * WORKFORCE_GOSI_RATE);
  const monthlyBaseCost = roundMoney(baseSalary + monthlyIqamaWorkPermit + gosiAmount + monthlyMedicalInsurance);
  const pricingMethod = source.pricing_method || "Margin Percent";
  const marginPercent = Number(source.margin_percent || 0);
  const manualMonthlyRate = Number(source.manual_monthly_rate || source.monthly_rate || 0);

  if (dealType === "Service Rental") {
    const calculatedMonthlyRate = pricingMethod === "Manual Monthly Rate" && manualMonthlyRate > 0
      ? manualMonthlyRate
      : roundMoney(monthlyBaseCost * (1 + marginPercent / 100));
    const subtotal = roundMoney(calculatedMonthlyRate * quantity * durationMonths);
    return {
      dealType,
      serviceType: "Service Rental",
      quantity,
      durationMonths,
      baseSalary,
      annualMedicalInsurance,
      monthlyIqamaWorkPermit,
      gosiRate: WORKFORCE_GOSI_RATE,
      gosiAmount,
      monthlyMedicalInsurance,
      monthlyBaseCost,
      pricingMethod,
      marginPercent,
      monthlyMargin: roundMoney(calculatedMonthlyRate - monthlyBaseCost),
      monthlyRate: roundMoney(calculatedMonthlyRate),
      subtotal,
      adminFee: 0,
      totalBeforeVat: subtotal,
      totalValue: subtotal,
      description: `Service Rental: ${quantity} worker(s) × ${durationMonths} month(s) × ${roundMoney(calculatedMonthlyRate).toLocaleString()} SAR`,
    };
  }

  const selectedWorkers = Array.isArray(source.selected_workers) ? source.selected_workers : [];
  const workersWithIqamaExpiry = selectedWorkers.filter((worker) => worker?.iqama_expiry_date);
  const enteredMonths = Number(source.transfer_remaining_months || 0);
  const fallbackRemainingMonths = enteredMonths > 0 ? enteredMonths : getMonthsUntil(source.iqama_expiry_date);
  const workerIqamaRemainingTotal = workersWithIqamaExpiry.length > 0 && enteredMonths <= 0
    ? roundMoney(workersWithIqamaExpiry.reduce((sum, worker) => sum + (monthlyIqamaWorkPermit * getMonthsUntil(worker.iqama_expiry_date)), 0))
    : 0;
  const iqamaRemainingTotal = workerIqamaRemainingTotal > 0
    ? workerIqamaRemainingTotal
    : roundMoney(monthlyIqamaWorkPermit * fallbackRemainingMonths * quantity);
  const iqamaRemainingCostPerWorker = quantity ? roundMoney(iqamaRemainingTotal / quantity) : 0;
  const remainingMonths = quantity ? roundMoney(iqamaRemainingCostPerWorker / monthlyIqamaWorkPermit) : fallbackRemainingMonths;

  const policyEndDate = source.insurance_policy_end_date || "";
  const getWorkerAnnualInsurance = (worker = {}) => {
    const workerAnnual = Number(worker.annual_medical_insurance || 0) || roundMoney(Number(worker.monthly_medical_insurance || 0) * 12);
    return workerAnnual > 0 ? workerAnnual : annualMedicalInsurance;
  };
  const getWorkerPolicyEndDate = (worker = {}) => worker.insurance_policy_end_date || policyEndDate;
  const medicalInsuranceRemainingTotal = selectedWorkers.length > 0
    ? roundMoney(selectedWorkers.reduce((sum, worker) => {
        const annual = getWorkerAnnualInsurance(worker);
        const days = getDaysUntil(getWorkerPolicyEndDate(worker));
        return sum + (annual * days / 365);
      }, 0))
    : roundMoney(annualMedicalInsurance * getDaysUntil(policyEndDate) / 365 * quantity);
  const medicalInsuranceRemainingPerWorker = quantity ? roundMoney(medicalInsuranceRemainingTotal / quantity) : 0;
  const insuranceRemainingDays = selectedWorkers.length > 0
    ? Math.max(...selectedWorkers.map((worker) => getDaysUntil(getWorkerPolicyEndDate(worker))), 0)
    : getDaysUntil(policyEndDate);

  const transferServiceFeePerWorker = Number(source.transfer_service_fee || 0);
  const transferBasePerWorker = roundMoney(iqamaRemainingCostPerWorker + medicalInsuranceRemainingPerWorker + transferServiceFeePerWorker);
  const transferSubtotal = roundMoney(iqamaRemainingTotal + medicalInsuranceRemainingTotal + (transferServiceFeePerWorker * quantity));
  const adminFeeMethod = source.admin_fee_method || "Percent";
  const adminFeePercent = Number(source.admin_fee_percent || 0);
  const adminFeeAmount = Number(source.admin_fee_amount || 0);
  const adminFee = adminFeeMethod === "Fixed Amount" ? roundMoney(adminFeeAmount) : roundMoney(transferSubtotal * adminFeePercent / 100);
  const totalValue = roundMoney(transferSubtotal + adminFee);

  return {
    dealType,
    serviceType: "Sponsorship Transfer",
    quantity,
    durationMonths: 0,
    baseSalary,
    annualMedicalInsurance,
    monthlyIqamaWorkPermit,
    gosiRate: WORKFORCE_GOSI_RATE,
    gosiAmount: 0,
    monthlyMedicalInsurance,
    remainingMonths,
    insuranceRemainingDays,
    iqamaExpiryDate: source.iqama_expiry_date || "",
    insurancePolicyEndDate: policyEndDate,
    iqamaRemainingTotal,
    workerIqamaRemainingTotal,
    iqamaRemainingCostPerWorker,
    medicalInsuranceRemainingPerWorker,
    medicalInsuranceRemainingTotal,
    transferServiceFeePerWorker,
    transferBasePerWorker,
    transferSubtotal,
    adminFeeMethod,
    adminFeePercent,
    adminFee,
    monthlyRate: 0,
    subtotal: transferSubtotal,
    totalBeforeVat: totalValue,
    totalValue,
    transferStatus: source.transfer_status || "Transfer Pending",
    description: `Sponsorship Transfer: iqama/work permit remaining + medical insurance calculated from annual policy value and remaining policy days + admin fees`,
  };
}

function buildMarketplaceInvoiceNotes(deal, breakdown) {
  if (!breakdown) return deal?.notes || "";
  const lines = [
    `Generated from deal ${deal?.deal_no || "-"}`,
    `Deal Type: ${breakdown.dealType}`,
    `Quantity: ${breakdown.quantity}`,
  ];

  if (breakdown.dealType === "Service Rental") {
    lines.push(
      `Monthly salary: ${Number(breakdown.baseSalary || 0).toLocaleString()} SAR`,
      `Monthly iqama + work permit: ${Number(breakdown.monthlyIqamaWorkPermit || 0).toLocaleString()} SAR`,
      `GOSI 2%: ${Number(breakdown.gosiAmount || 0).toLocaleString()} SAR`,
      `Annual medical insurance / worker: ${Number(breakdown.annualMedicalInsurance || 0).toLocaleString()} SAR`,
      `Medical insurance / month: ${Number(breakdown.monthlyMedicalInsurance || 0).toLocaleString()} SAR`,
      `Monthly base cost: ${Number(breakdown.monthlyBaseCost || 0).toLocaleString()} SAR`,
      `Monthly rental rate: ${Number(breakdown.monthlyRate || 0).toLocaleString()} SAR`,
      `Duration: ${breakdown.durationMonths} month(s)`
    );
  } else {
    lines.push(
      `Average iqama remaining months: ${breakdown.remainingMonths}`,
      `Iqama + work permit remaining total: ${Number(breakdown.iqamaRemainingTotal || 0).toLocaleString()} SAR`,
      `Annual medical insurance / worker: ${Number(breakdown.annualMedicalInsurance || 0).toLocaleString()} SAR`,
      `Medical insurance remaining total: ${Number(breakdown.medicalInsuranceRemainingTotal || 0).toLocaleString()} SAR`,
      `Transfer service fee / worker: ${Number(breakdown.transferServiceFeePerWorker || 0).toLocaleString()} SAR`,
      `Admin fee: ${Number(breakdown.adminFee || 0).toLocaleString()} SAR`
    );
  }

  if (deal?.notes) lines.push(`Deal notes: ${deal.notes}`);
  return lines.filter(Boolean).join("\n");
}


function getMarketplaceDealCalculationSource(deal = {}) {
  const dbWorkers = getMarketplaceDealWorkerRows(deal);
  const snapshotWorkers = Array.isArray(deal.selected_workers) ? deal.selected_workers : [];
  const workers = dbWorkers.length > 0 ? dbWorkers : snapshotWorkers;
  return {
    ...deal,
    selected_workers: workers,
    quantity: workers.length || Number(deal.quantity || 0),
  };
}

function buildWorkforceCalculationRows(deal = {}, breakdown = {}) {
  const rows = [];
  const qty = Number(breakdown.quantity || deal.quantity || 0);

  rows.push({ Section: "Deal", Item: "Deal No", Formula: "-", Value: deal.deal_no || "-", Unit: "" });
  rows.push({ Section: "Deal", Item: "Client", Formula: "-", Value: deal.client_name || "-", Unit: "" });
  rows.push({ Section: "Deal", Item: "Deal Type", Formula: "-", Value: breakdown.dealType || getWorkforceDealType(deal), Unit: "" });
  rows.push({ Section: "Deal", Item: "Profession", Formula: "-", Value: deal.profession || "-", Unit: "" });
  rows.push({ Section: "Deal", Item: "Quantity", Formula: "-", Value: qty, Unit: "worker(s)" });

  if (breakdown.dealType === "Service Rental") {
    rows.push({ Section: "Monthly Cost", Item: "Monthly Salary / Worker", Formula: "Manual input", Value: roundMoney(breakdown.baseSalary), Unit: "SAR" });
    rows.push({ Section: "Monthly Cost", Item: "Iqama + Work Permit / Month / Worker", Formula: "Fixed platform rule", Value: roundMoney(breakdown.monthlyIqamaWorkPermit), Unit: "SAR" });
    rows.push({ Section: "Monthly Cost", Item: "GOSI / Worker", Formula: "Monthly Salary × 2%", Value: roundMoney(breakdown.gosiAmount), Unit: "SAR" });
    rows.push({ Section: "Monthly Cost", Item: "Annual Medical Insurance / Worker", Formula: "Manual input", Value: roundMoney(breakdown.annualMedicalInsurance), Unit: "SAR" });
    rows.push({ Section: "Monthly Cost", Item: "Medical Insurance / Month / Worker", Formula: "Annual Medical Insurance ÷ 12", Value: roundMoney(breakdown.monthlyMedicalInsurance), Unit: "SAR" });
    rows.push({ Section: "Monthly Cost", Item: "Monthly Base Cost / Worker", Formula: "Salary + Iqama/Work Permit + GOSI + Medical Insurance Monthly", Value: roundMoney(breakdown.monthlyBaseCost), Unit: "SAR" });
    rows.push({ Section: "Pricing", Item: "Pricing Method", Formula: "Manual selection", Value: breakdown.pricingMethod || "Margin Percent", Unit: "" });
    rows.push({ Section: "Pricing", Item: "Margin %", Formula: "Manual input", Value: Number(breakdown.marginPercent || 0), Unit: "%" });
    rows.push({ Section: "Pricing", Item: "Monthly Margin / Worker", Formula: "Monthly Rate - Monthly Base Cost", Value: roundMoney(breakdown.monthlyMargin), Unit: "SAR" });
    rows.push({ Section: "Pricing", Item: "Monthly Rental Rate / Worker", Formula: "Monthly Base Cost × (1 + Margin %) OR Manual Monthly Rate", Value: roundMoney(breakdown.monthlyRate), Unit: "SAR" });
    rows.push({ Section: "Totals", Item: "Duration", Formula: "Manual input", Value: Number(breakdown.durationMonths || 0), Unit: "month(s)" });
    rows.push({ Section: "Totals", Item: "Subtotal Before VAT", Formula: "Monthly Rental Rate × Quantity × Duration", Value: roundMoney(breakdown.totalValue), Unit: "SAR" });
  } else {
    rows.push({ Section: "Fixed Rules", Item: "Iqama + Work Permit / Month / Worker", Formula: "Fixed platform rule", Value: roundMoney(breakdown.monthlyIqamaWorkPermit), Unit: "SAR" });
    rows.push({ Section: "Iqama", Item: "Average Remaining Months", Formula: "Average of each selected worker's remaining iqama months", Value: roundMoney(breakdown.remainingMonths), Unit: "month(s)" });
    rows.push({ Section: "Iqama", Item: "Iqama + Work Permit Remaining Total", Formula: "Σ(862.5 × remaining months per worker)", Value: roundMoney(breakdown.iqamaRemainingTotal), Unit: "SAR" });
    rows.push({ Section: "Medical Insurance", Item: "Annual Medical Insurance / Worker", Formula: "Manual input", Value: roundMoney(breakdown.annualMedicalInsurance), Unit: "SAR" });
    rows.push({ Section: "Medical Insurance", Item: "Insurance Policy End Date", Formula: "Manual input / employee data", Value: breakdown.insurancePolicyEndDate || "From selected workers", Unit: "" });
    rows.push({ Section: "Medical Insurance", Item: "Max Remaining Policy Days", Formula: "Policy end date - today", Value: Number(breakdown.insuranceRemainingDays || 0), Unit: "day(s)" });
    rows.push({ Section: "Medical Insurance", Item: "Medical Insurance Remaining Total", Formula: "Σ(Annual Medical Insurance ÷ 365 × remaining policy days per worker)", Value: roundMoney(breakdown.medicalInsuranceRemainingTotal), Unit: "SAR" });
    rows.push({ Section: "Transfer", Item: "Transfer / Service Fee / Worker", Formula: "Manual input", Value: roundMoney(breakdown.transferServiceFeePerWorker), Unit: "SAR" });
    rows.push({ Section: "Transfer", Item: "Transfer Service Fee Total", Formula: "Transfer / Service Fee / Worker × Quantity", Value: roundMoney(Number(breakdown.transferServiceFeePerWorker || 0) * qty), Unit: "SAR" });
    rows.push({ Section: "Transfer", Item: "Transfer Subtotal", Formula: "Iqama Remaining + Medical Remaining + Transfer Service Fee Total", Value: roundMoney(breakdown.transferSubtotal), Unit: "SAR" });
    rows.push({ Section: "Admin Fee", Item: "Admin Fee Method", Formula: "Manual selection", Value: breakdown.adminFeeMethod || "Percent", Unit: "" });
    rows.push({ Section: "Admin Fee", Item: "Admin Fee %", Formula: "Manual input", Value: Number(breakdown.adminFeePercent || 0), Unit: "%" });
    rows.push({ Section: "Admin Fee", Item: "Admin Fee Amount", Formula: "Transfer Subtotal × Admin Fee % OR Fixed Amount", Value: roundMoney(breakdown.adminFee), Unit: "SAR" });
    rows.push({ Section: "Totals", Item: "Subtotal Before VAT", Formula: "Transfer Subtotal + Admin Fee", Value: roundMoney(breakdown.totalValue), Unit: "SAR" });
  }

  const vat = roundMoney(Number(breakdown.totalValue || 0) * WORKFORCE_VAT_RATE);
  rows.push({ Section: "VAT", Item: "VAT Rate", Formula: "Platform invoice rule", Value: WORKFORCE_VAT_RATE * 100, Unit: "%" });
  rows.push({ Section: "VAT", Item: "VAT Amount", Formula: "Subtotal Before VAT × VAT Rate", Value: vat, Unit: "SAR" });
  rows.push({ Section: "Grand Total", Item: "Total Including VAT", Formula: "Subtotal Before VAT + VAT Amount", Value: roundMoney(Number(breakdown.totalValue || 0) + vat), Unit: "SAR" });

  return rows;
}

function buildWorkforceWorkerCalculationRows(deal = {}, breakdown = {}) {
  const source = getMarketplaceDealCalculationSource(deal);
  const workers = Array.isArray(source.selected_workers) ? source.selected_workers : [];
  const annualFallback = Number(breakdown.annualMedicalInsurance || deal.annual_medical_insurance || 0);
  const policyEndFallback = breakdown.insurancePolicyEndDate || deal.insurance_policy_end_date || "";

  if (!workers.length) {
    return [{
      "Employee No": "Manual quantity only",
      "Employee Name": "No selected worker rows attached",
      "Iqama No": "-",
      "Iqama Expiry Date": deal.iqama_expiry_date || "-",
      "Iqama Remaining Months": getMonthsUntil(deal.iqama_expiry_date),
      "Iqama Remaining Cost": roundMoney(WORKFORCE_MONTHLY_IQAMA_WORK_PERMIT_COST * getMonthsUntil(deal.iqama_expiry_date)),
      "Insurance Policy End Date": policyEndFallback || "-",
      "Annual Medical Insurance": annualFallback,
      "Insurance Remaining Days": getDaysUntil(policyEndFallback),
      "Medical Insurance Remaining": roundMoney(annualFallback * getDaysUntil(policyEndFallback) / 365),
    }];
  }

  return workers.map((worker, index) => {
    const annual = Number(worker.annual_medical_insurance || 0) || annualFallback;
    const policyEnd = worker.insurance_policy_end_date || policyEndFallback;
    const iqamaMonths = getMonthsUntil(worker.iqama_expiry_date);
    const insuranceDays = getDaysUntil(policyEnd);
    return {
      "#": index + 1,
      "Employee No": worker.employee_no || "",
      "Employee Name": worker.employee_name || "",
      "Iqama No": worker.iqama_no || "",
      "Profession": worker.profession || deal.profession || "",
      "Nationality": worker.nationality || deal.nationality || "",
      "Gender": worker.gender || deal.gender || "",
      "Project": worker.project_name || "",
      "Iqama Expiry Date": worker.iqama_expiry_date || "",
      "Iqama Remaining Months": iqamaMonths,
      "Iqama + Work Permit Monthly": WORKFORCE_MONTHLY_IQAMA_WORK_PERMIT_COST,
      "Iqama Remaining Cost": roundMoney(WORKFORCE_MONTHLY_IQAMA_WORK_PERMIT_COST * iqamaMonths),
      "Insurance Policy End Date": policyEnd || "",
      "Annual Medical Insurance": annual,
      "Insurance Remaining Days": insuranceDays,
      "Medical Insurance Remaining": roundMoney(annual * insuranceDays / 365),
    };
  });
}

function exportWorkforceAgreementCalculationExcel(deal = {}) {
  const source = getMarketplaceDealCalculationSource(deal);
  const breakdown = getMarketplacePricingBreakdown(source);
  const agreementText = deal.agreement_text || buildWorkforceAgreementText(source);
  const vat = roundMoney(Number(breakdown.totalValue || 0) * WORKFORCE_VAT_RATE);
  const totalWithVat = roundMoney(Number(breakdown.totalValue || 0) + vat);

  const summaryRows = [
    { Field: "Deal No", Value: deal.deal_no || "-" },
    { Field: "Agreement No", Value: deal.agreement_no || "Not generated" },
    { Field: "Client", Value: deal.client_name || "-" },
    { Field: "Deal Type", Value: breakdown.dealType },
    { Field: "Profession", Value: deal.profession || "-" },
    { Field: "Quantity", Value: breakdown.quantity },
    { Field: "Total Before VAT", Value: roundMoney(breakdown.totalValue), Unit: "SAR" },
    { Field: "VAT 15%", Value: vat, Unit: "SAR" },
    { Field: "Total Including VAT", Value: totalWithVat, Unit: "SAR" },
    { Field: "Generated At", Value: new Date().toLocaleString("en-GB") },
  ];

  const workbook = XLSX.utils.book_new();
  const summarySheet = XLSX.utils.json_to_sheet(summaryRows);
  const calcSheet = XLSX.utils.json_to_sheet(buildWorkforceCalculationRows(source, breakdown));
  const workersSheet = XLSX.utils.json_to_sheet(buildWorkforceWorkerCalculationRows(source, breakdown));
  const agreementSheet = XLSX.utils.aoa_to_sheet(
    String(agreementText || "")
      .split("\n")
      .map((line) => [line])
  );

  summarySheet["!cols"] = [{ wch: 28 }, { wch: 36 }, { wch: 14 }];
  calcSheet["!cols"] = [{ wch: 20 }, { wch: 42 }, { wch: 70 }, { wch: 20 }, { wch: 12 }];
  workersSheet["!cols"] = [
    { wch: 6 }, { wch: 18 }, { wch: 26 }, { wch: 16 }, { wch: 26 }, { wch: 18 }, { wch: 10 }, { wch: 22 },
    { wch: 18 }, { wch: 22 }, { wch: 24 }, { wch: 22 }, { wch: 22 }, { wch: 24 }, { wch: 24 }, { wch: 28 },
  ];
  agreementSheet["!cols"] = [{ wch: 120 }];

  XLSX.utils.book_append_sheet(workbook, summarySheet, "Summary");
  XLSX.utils.book_append_sheet(workbook, calcSheet, "Calculation");
  XLSX.utils.book_append_sheet(workbook, workersSheet, "Workers");
  XLSX.utils.book_append_sheet(workbook, agreementSheet, "Agreement Text");

  const safeDealNo = String(deal.deal_no || "workforce_deal").replace(/[^a-zA-Z0-9_-]/g, "_");
  XLSX.writeFile(workbook, `VisaFlow_${safeDealNo}_Calculation.xlsx`);
}

function buildWorkforceAgreementText(deal = {}) {
  const breakdown = getMarketplacePricingBreakdown(deal);
  const agreementNo = deal.agreement_no || generateMarketplaceNo("WFA", marketplaceDeals, "agreement_no", 5);
  const today = new Date().toISOString().slice(0, 10);

  if (breakdown.dealType === "Service Rental") {
    return `WORKFORCE SERVICE RENTAL AGREEMENT / اتفاقية تأجير خدمات عمالة

Agreement No: ${agreementNo}
Date: ${today}
Client: ${deal.client_name || "-"}
Profession: ${deal.profession || "-"}
Quantity: ${breakdown.quantity}
Duration: ${breakdown.durationMonths} month(s)
Monthly Rental Rate / Worker: ${Number(breakdown.monthlyRate || 0).toLocaleString()} SAR

The monthly rental rate includes salary, iqama/work permit cost at ${WORKFORCE_MONTHLY_IQAMA_WORK_PERMIT_COST} SAR per month, GOSI at 2% of salary, and medical insurance calculated from the annual policy value entered by the company, plus the approved margin or manual monthly rate.

تشمل القيمة الإيجارية الشهرية الراتب ورسوم الإقامة ورخصة العمل بواقع ${WORKFORCE_MONTHLY_IQAMA_WORK_PERMIT_COST} ريال شهرياً، والتأمينات بنسبة 2% من الراتب، والتأمين الطبي المحتسب من قيمة الوثيقة السنوية المدخلة من الشركة، وهامش التسعير أو السعر الشهري اليدوي المعتمد.

Total Before VAT: ${Number(breakdown.totalValue || 0).toLocaleString()} SAR`;
  }

  return `SPONSORSHIP TRANSFER AGREEMENT / اتفاقية تنازل ونقل كفالة

Agreement No: ${agreementNo}
Date: ${today}
Client: ${deal.client_name || "-"}
Profession: ${deal.profession || "-"}
Quantity: ${breakdown.quantity}
Transfer Status: ${deal.transfer_status || "Transfer Pending"}

The transfer invoice includes the remaining iqama/work permit cost until expiry, medical insurance remaining value calculated from the annual insurance value and remaining policy days, transfer/service fees, and administrative fees approved by the company.

تشمل فاتورة التنازل تكلفة الإقامة ورخصة العمل المتبقية حتى تاريخ الانتهاء، وقيمة التأمين الطبي المتبقية المحسوبة من قيمة التأمين السنوية والأيام المتبقية من الوثيقة، ورسوم الخدمة أو التنازل، والرسوم الإدارية المعتمدة.

If sponsorship transfer is not completed, the company may convert this deal into a service rental case and calculate monthly rental fees from the worker handover/start date according to the approved monthly rental rate.

في حال عدم إتمام نقل الكفالة، يحق للشركة تحويل العملية إلى تأجير خدمات واحتساب القيمة الإيجارية الشهرية من تاريخ تسليم/بدء العامل حسب السعر الشهري المعتمد.

Total Before VAT: ${Number(breakdown.totalValue || 0).toLocaleString()} SAR`;
}

async function generateWorkforceAgreement(deal) {
  if (!canManageMarketplace) return alert("You do not have permission to generate agreements.");
  const source = getMarketplaceDealCalculationSource(deal);
  const agreementNo = deal.agreement_no || generateMarketplaceNo("WFA", marketplaceDeals, "agreement_no", 5);
  const agreementText = buildWorkforceAgreementText({ ...source, agreement_no: agreementNo });
  const breakdown = getMarketplacePricingBreakdown({ ...source, agreement_no: agreementNo });

  const { error } = await supabase
    .from("marketplace_deals")
    .update(withUpdateActor({
      agreement_no: agreementNo,
      agreement_status: "Generated",
      agreement_text: agreementText,
      calc_breakdown: breakdown,
      total_value: Number(breakdown.totalValue || deal.total_value || 0),
      updated_at: new Date().toISOString(),
    }))
    .eq("id", deal.id)
    .eq("company_id", currentCompanyId);

  if (error) return alert(error.message);

  exportWorkforceAgreementCalculationExcel({
    ...source,
    agreement_no: agreementNo,
    agreement_status: "Generated",
    agreement_text: agreementText,
    calc_breakdown: breakdown,
    total_value: Number(breakdown.totalValue || deal.total_value || 0),
  });

  await loadMarketplaceDeals();
  alert(`Agreement generated and calculation Excel downloaded: ${agreementNo}`);
}

async function convertMarketplaceTransferToRental(deal) {
  if (!canManageMarketplace) return alert("You do not have permission to convert deals.");
  if (getWorkforceDealType(deal) !== "Sponsorship Transfer") return alert("Only sponsorship transfer deals can be converted to rental.");

  const monthlyRateText = window.prompt("Monthly rental rate per worker:", String(deal.manual_monthly_rate || deal.monthly_rate || ""));
  if (!monthlyRateText) return;
  const monthsText = window.prompt("Rental duration in months:", "1");
  if (!monthsText) return;

  const monthlyRate = Number(monthlyRateText || 0);
  const durationMonths = Number(monthsText || 1);
  if (!monthlyRate || monthlyRate <= 0) return alert("Monthly rental rate must be greater than zero.");

  const qty = Number(deal.quantity || 1);
  const totalValue = roundMoney(qty * monthlyRate * durationMonths);
  const notes = [
    deal.notes || "",
    `[${new Date().toLocaleDateString("en-GB")}] Transfer was converted to Service Rental. Monthly rate: ${monthlyRate.toLocaleString()} SAR, Duration: ${durationMonths} month(s).`,
  ].filter(Boolean).join("\n");

  const { error } = await supabase
    .from("marketplace_deals")
    .update(withUpdateActor({
      deal_type: "Service Rental",
      service_type: "Service Rental",
      pricing_method: "Manual Monthly Rate",
      manual_monthly_rate: monthlyRate,
      monthly_rate: monthlyRate,
      duration_months: durationMonths,
      transfer_status: "Converted to Rental",
      status: "Converted to Rental",
      total_value: totalValue,
      calc_breakdown: getMarketplacePricingBreakdown({ ...deal, deal_type: "Service Rental", pricing_method: "Manual Monthly Rate", manual_monthly_rate: monthlyRate, monthly_rate: monthlyRate, duration_months: durationMonths }),
      notes,
      updated_at: new Date().toISOString(),
    }))
    .eq("id", deal.id)
    .eq("company_id", currentCompanyId);

  if (error) return alert(error.message);
  alert("Transfer deal converted to rental.");
  await loadMarketplaceDeals();
}

